import React, { useState, useEffect, useMemo, createContext, useContext, useRef } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, useNavigate } from 'react-router-dom';
import { 
  LayoutDashboard, Wallet, PiggyBank, Receipt, BarChart3, 
  MessageSquare, ChevronLeft, ChevronRight, Menu, X, Plus, 
  Camera, CalendarDays, CalendarRange, Sun, Moon, 
  LineChart as LineChartIcon, TrendingUp, Calendar as CalendarIcon,
  LogOut, Loader2, Sparkles
} from 'lucide-react';
import { FinanceState, Account, Saving, Refund, Transaction, Budget, AIChallenge } from './types';
import { INITIAL_DATA } from './constants';
import { supabase } from './services/supabase';

// Componentes de vistas
import Dashboard from './components/Dashboard.tsx';
import Accounts from './components/Accounts.tsx';
import Savings from './components/Savings.tsx';
import Refunds from './components/Refunds.tsx';
import Transactions from './components/Transactions.tsx';
import BudgetManager from './components/Budget.tsx';
import AIAdvisor from './components/AIAdvisor.tsx';
import WealthProjections from './components/WealthProjections.tsx';
import Login from './components/Login.tsx';

interface FinanceContextType extends FinanceState {
  getAccountHistoricalBalance: (accountId: string, dateStr: string) => number;
  getSavingHistoricalBalance: (savingId: string, dateStr: string) => number;
  addTransaction: (t: Omit<Transaction, 'id'>, myPart?: number) => void;
  updateTransaction: (t: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addAccount: (a: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (a: Account) => void;
  deleteAccount: (id: string) => void;
  addSaving: (s: Omit<Saving, 'id'>) => void;
  updateSaving: (s: Saving) => void;
  deleteSaving: (id: string) => void;
  addRefund: (r: Omit<Refund, 'id'>) => void;
  updateRefund: (r: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addBudget: (b: Omit<Budget, 'id' | 'spent' | 'icon' | 'type'> & { type?: 'income' | 'expense'; icon?: string }) => void;
  updateBudget: (b: Budget) => void;
  deleteBudget: (id: string) => void;
  changePeriod: (offset: number) => void;
  setPeriod: (date: string) => void;
  setViewMode: (mode: 'month' | 'year') => void;
  updateLayout: (newLayout: string[]) => void;
  setChallenges: (challenges: AIChallenge[]) => void;
  toggleTheme: () => void;
  isGuest: boolean;
  loginAsGuest: () => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);
export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [state, setState] = useState<FinanceState>(INITIAL_DATA as any);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // Manejo de Sesión (Supabase + LocalStorage fallback)
  useEffect(() => {
    const checkSession = async () => {
      const { data: { session } } = await supabase.auth.getSession();

      const guestFlag = localStorage.getItem('finanzas_pro_guest') === 'true';

      if (session) {
        setSession(session);
        setIsGuest(false);
        fetchUserData(session.user.id);
      } else if (guestFlag) {
        setIsGuest(true);
        const savedState = localStorage.getItem('finanzas_pro_local_state');
        if (savedState) {
          setState(JSON.parse(savedState));
        }
        setIsLoading(false);
      } else {
        setIsLoading(false);
      }
    };

    checkSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session) {
        setSession(session);
        setIsGuest(false);
        fetchUserData(session.user.id);
      } else if (localStorage.getItem('finanzas_pro_guest') !== 'true') {
        setSession(null);
        setState(INITIAL_DATA as any);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchUserData = async (userId: string) => {
    setIsLoading(true);
    const { data, error } = await supabase
      .from('profiles')
      .select('state')
      .eq('id', userId)
      .single();

    if (data && data.state) {
      setState(data.state);
    } else if (error && error.code === 'PGRST116') {
      await supabase.from('profiles').upsert({ id: userId, state: INITIAL_DATA });
      setState(INITIAL_DATA as any);
    }
    setIsLoading(false);
  };

  // Persistencia dual
  useEffect(() => {
    if (!isLoading) {
      if (session) {
        const timer = setTimeout(async () => {
          await supabase.from('profiles').upsert({ id: session.user.id, state });
        }, 1000);
        return () => clearTimeout(timer);
      } else if (isGuest) {
        localStorage.setItem('finanzas_pro_local_state', JSON.stringify(state));
      }
    }
  }, [state, session, isGuest, isLoading]);

  useEffect(() => {
    if (state.theme === 'dark') document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [state.theme]);

  const getAccountHistoricalBalance = (accountId: string, dateLimit: string) => {
    const account = state.accounts.find(a => a.id === accountId);
    if (!account) return 0;
    let endDay = dateLimit.length === 4 ? `${dateLimit}-12-31` : `${dateLimit}-31`; 
    const relevantTransactions = state.transactions.filter(t => t.accountId === accountId && t.date <= endDay);
    return relevantTransactions.reduce((acc, t) => acc + (t.type === 'income' ? t.amount : -t.amount), account.initialBalance);
  };

  const getSavingHistoricalBalance = (savingId: string, dateLimit: string) => {
    const relevant = state.transactions.filter(t => t.savingId === savingId && t.date <= (dateLimit.length === 4 ? `${dateLimit}-12-31` : `${dateLimit}-31`));
    return relevant.reduce((acc, t) => acc + t.amount, 0);
  };

  const loginAsGuest = () => {
    localStorage.setItem('finanzas_pro_guest', 'true');
    setIsGuest(true);
    const saved = localStorage.getItem('finanzas_pro_local_state');
    if (saved) setState(JSON.parse(saved));
    else setState(INITIAL_DATA as any);
  };

  const logout = () => {
    localStorage.removeItem('finanzas_pro_guest');
    localStorage.removeItem('finanzas_pro_local_state');
    setIsGuest(false);
    setSession(null);
    supabase.auth.signOut();
  };

  if (isLoading) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950">
        <Loader2 className="animate-spin text-blue-600 mb-4" size={48} />
        <p className="text-slate-400 font-black uppercase tracking-widest text-[10px]">Cargando tu estrategia...</p>
      </div>
    );
  }

  if (!session && !isGuest) {
    return <Login onGuestLogin={loginAsGuest} />;
  }

  const contextValue: FinanceContextType = {
    ...state,
    getAccountHistoricalBalance,
    getSavingHistoricalBalance,
    isGuest,
    loginAsGuest,
    addTransaction: (t, myPart) => {
      const id = 'tx_' + Math.random().toString(36).substr(2, 9);
      let finalTx = { ...t, id };
      let newRefunds = [...state.refunds];
      if (t.type === 'expense' && t.isRefund) {
        const refundId = 'ref_' + Date.now();
        const partToPay = myPart !== undefined ? myPart : t.amount / 2;
        newRefunds.push({ id: refundId, name: t.description, totalAmount: t.amount, paidByMe: partToPay, pendingAmount: t.amount - partToPay, status: 'open', notes: 'Auto', date: t.date, category: t.category, originTransactionId: id });
        finalTx.refundId = refundId;
      }
      setState(prev => ({ ...prev, transactions: [finalTx as Transaction, ...prev.transactions], refunds: newRefunds }));
    },
    updateTransaction: (updatedTx) => setState(prev => ({ ...prev, transactions: prev.transactions.map(t => t.id === updatedTx.id ? updatedTx : t) })),
    deleteTransaction: (id) => setState(prev => ({ ...prev, transactions: prev.transactions.filter(tx => tx.id !== id) })),
    addAccount: (a) => setState(prev => ({ ...prev, accounts: [...prev.accounts, { ...a, id: 'acc_' + Date.now(), currentBalance: a.initialBalance } as Account] })),
    updateAccount: (a) => setState(prev => ({ ...prev, accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc) })),
    deleteAccount: (id) => setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) })),
    addSaving: (s) => setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id: 'sav_' + Date.now() } as Saving] })),
    updateSaving: (s) => setState(prev => ({ ...prev, savings: prev.savings.map(sv => sv.id === s.id ? s : sv) })),
    deleteSaving: (id) => setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) })),
    addRefund: (r) => setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id: 'ref_' + Date.now() } as Refund] })),
    updateRefund: (r) => setState(prev => ({ ...prev, refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf) })),
    deleteRefund: (id) => setState(prev => ({ ...prev, refunds: prev.refunds.filter(r => r.id !== id) })),
    mergeRefunds: (id1, id2) => {
      const r1 = state.refunds.find(r => r.id === id1);
      const r2 = state.refunds.find(r => r.id === id2);
      if (!r1 || !r2) return;
      const merged: Refund = {
        id: 'ref_' + Date.now(),
        name: `${r1.name} + ${r2.name}`,
        totalAmount: r1.totalAmount + r2.totalAmount,
        paidByMe: r1.paidByMe + r2.paidByMe,
        pendingAmount: r1.pendingAmount + r2.pendingAmount,
        status: (r1.status === 'open' || r2.status === 'open') ? 'open' : 'closed',
        notes: `Fusionado: ${r1.notes} | ${r2.notes}`,
        date: new Date().toISOString(),
        category: r1.category
      };
      setState(prev => ({
        ...prev,
        refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), merged]
      }));
    },
    addBudget: (b) => setState(prev => ({ ...prev, budgets: [...prev.budgets, { ...b, id: 'budget_' + Date.now(), spent: 0 } as Budget] })),
    updateBudget: (b) => setState(prev => ({ ...prev, budgets: prev.budgets.map(bg => bg.id === b.id ? b : bg) })),
    deleteBudget: (id) => setState(prev => ({ ...prev, budgets: prev.budgets.filter(b => b.id !== id) })),
    changePeriod: (offset) => {
      const [year, month] = state.currentDate.split('-').map(Number);
      const newDate = new Date(year, (month || 1) - 1 + offset, 1);
      const newDateStr = state.viewMode === 'year' ? newDate.getFullYear().toString() : `${newDate.getFullYear()}-${String(newDate.getMonth() + 1).padStart(2, '0')}`;
      setState(prev => ({ ...prev, currentDate: newDateStr }));
    },
    setPeriod: (dateStr) => setState(prev => ({ ...prev, currentDate: dateStr })),
    setViewMode: (mode) => setState(prev => ({ ...prev, viewMode: mode })),
    updateLayout: (newLayout) => setState(prev => ({ ...prev, dashboardLayout: newLayout })),
    setChallenges: (challenges) => setState(prev => ({ ...prev, challenges })),
    toggleTheme: () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }))
  };

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 overflow-hidden text-slate-900 dark:text-slate-100">
          <Sidebar isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} onLogout={logout} isGuest={isGuest} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={() => setIsMenuOpen(true)} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/wealth" element={<WealthProjections />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

const Sidebar = ({ isOpen, onClose, onLogout, isGuest }: { isOpen: boolean, onClose: () => void, onLogout: () => void, isGuest: boolean }) => {
  const location = useLocation();
  const menuItems = [
    { path: '/', icon: <LayoutDashboard size={20} />, label: 'Dashboard' },
    { path: '/accounts', icon: <Wallet size={20} />, label: 'Cuentas' },
    { path: '/savings', icon: <PiggyBank size={20} />, label: 'Ahorro' },
    { path: '/wealth', icon: <LineChartIcon size={20} />, label: 'Proyecciones' },
    { path: '/refunds', icon: <Receipt size={20} />, label: 'Reembolsos' },
    { path: '/transactions', icon: <BarChart3 size={20} />, label: 'Transacciones' },
    { path: '/budget', icon: <Receipt size={20} />, label: 'Presupuesto' },
    { path: '/advisor', icon: <MessageSquare size={20} />, label: 'Asesor IA' },
  ];
  return (
    <>
      {isOpen && <div className="fixed inset-0 bg-slate-900/60 dark:bg-black/60 backdrop-blur-sm z-40 md:hidden" onClick={onClose} />}
      <aside className={`fixed md:static inset-y-0 left-0 w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 shadow-xl md:shadow-sm z-50 flex flex-col transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <div className="p-6 flex items-center justify-between">
          <h1 className="text-xl font-bold text-blue-600 dark:text-blue-400 flex items-center gap-2">
            <div className="w-8 h-8 bg-blue-600 dark:bg-blue-500 rounded-lg flex items-center justify-center text-white"><Wallet size={18} /></div>
            Finanzas Pro
          </h1>
          <button onClick={onClose} className="md:hidden p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"><X size={20} /></button>
        </div>

        {isGuest && (
          <div className="mx-4 mb-4 p-3 bg-amber-50 dark:bg-amber-900/20 rounded-xl border border-amber-100 dark:border-amber-800 flex items-center gap-3">
             <Sparkles className="text-amber-500" size={16} />
             <div className="flex-1">
               <p className="text-[10px] font-black text-amber-600 dark:text-amber-400 uppercase tracking-widest">Modo Invitado</p>
               <p className="text-[8px] text-amber-500 font-medium leading-tight">Guardado en este navegador</p>
             </div>
          </div>
        )}

        <nav className="flex-1 px-4 space-y-1 overflow-y-auto custom-scrollbar">
          {menuItems.map((item) => (
            <Link key={item.path} to={item.path} onClick={onClose} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 ${location.pathname === item.path ? 'bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 font-semibold shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-800 dark:hover:text-slate-200'}`}>
              {item.icon} {item.label}
            </Link>
          ))}
        </nav>
        <div className="p-4 border-t border-slate-100 dark:border-slate-800">
           <button onClick={onLogout} className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl transition-all font-bold">
             <LogOut size={20} /> Salir
           </button>
        </div>
      </aside>
    </>
  );
};

const Header = ({ onMenuClick }: { onMenuClick: () => void }) => {
  const { currentDate, changePeriod, viewMode, setViewMode, theme, toggleTheme } = useFinance();
  const monthNames = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];

  const currentFormatted = useMemo(() => {
    if (viewMode === 'year') return `Año ${currentDate}`;
    const parts = currentDate.split('-').map(Number);
    return parts.length === 2 ? `${monthNames[parts[1] - 1] || ''} ${parts[0]}` : currentDate;
  }, [currentDate, viewMode]);

  return (
    <header className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 h-16 flex items-center justify-between px-4 md:px-6 sticky top-0 z-40 transition-all duration-300">
      <div className="flex items-center gap-3">
        <button onClick={onMenuClick} className="md:hidden p-2 text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"><Menu size={22} /></button>
        <div className="flex items-center gap-2">
          <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-xl shadow-inner mr-2">
             <button onClick={() => setViewMode('month')} className={`p-1.5 rounded-lg transition-all ${viewMode === 'month' ? 'bg-white dark:bg-slate-700 shadow-sm text-blue-600 dark:text-blue-400' : 'text-slate-400'}`}><CalendarDays size={18} /></button>
             <button onClick={() => setViewMode('year')} className={`p-1.5 rounded-lg transition-all ${viewMode === 'year' ? 'bg-white dark:bg-slate-700 shadow-sm text-blue-600 dark:text-blue-400' : 'text-slate-400'}`}><CalendarRange size={18} /></button>
          </div>
          <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-xl shadow-inner">
            <button onClick={() => changePeriod(-1)} className="p-1 hover:bg-white dark:hover:bg-slate-700 rounded-lg transition-all dark:text-slate-400"><ChevronLeft size={18} /></button>
            <span className="px-3 py-1.5 text-xs font-black text-slate-700 dark:text-slate-300 min-w-[110px] text-center uppercase tracking-wider">{currentFormatted}</span>
            <button onClick={() => changePeriod(1)} className="p-1 hover:bg-white dark:hover:bg-slate-700 rounded-lg transition-all dark:text-slate-400"><ChevronRight size={18} /></button>
          </div>
        </div>
      </div>
      <button onClick={toggleTheme} className="p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 shadow-sm transition-all">
        {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
      </button>
    </header>
  );
};

const QuickAddButton = () => {
  const [open, setOpen] = useState(false);
  const navigate = useNavigate();
  return (
    <div className="fixed bottom-6 right-6 md:bottom-8 md:right-8 z-40">
      {open && (
        <div className="absolute bottom-16 right-0 mb-2 flex flex-col gap-2 animate-in slide-in-from-bottom-4 duration-300">
          <button onClick={() => { setOpen(false); navigate('/transactions', { state: { triggerScan: true } }); }} className="flex items-center gap-3 bg-blue-50 dark:bg-blue-900 text-blue-700 dark:text-blue-300 px-5 py-4 rounded-2xl shadow-xl border border-blue-100 dark:border-blue-800 whitespace-nowrap group">
            <Camera size={20} /> <span className="text-sm font-black uppercase tracking-widest">Aura Vision</span>
          </button>
          <button onClick={() => { setOpen(false); navigate('/transactions', { state: { openModal: true } }); }} className="flex items-center gap-3 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 px-5 py-4 rounded-2xl shadow-xl border border-slate-100 dark:border-slate-700 whitespace-nowrap">
            <Receipt size={20} /> <span className="text-sm font-black uppercase tracking-widest">Nuevo Movimiento</span>
          </button>
          <button onClick={() => { setOpen(false); navigate('/advisor'); }} className="flex items-center gap-3 bg-blue-600 text-white px-5 py-4 rounded-2xl shadow-xl hover:bg-blue-700 transition-all">
            <MessageSquare size={20} /> <span className="text-sm font-black uppercase tracking-widest">Hablar con Aura</span>
          </button>
        </div>
      )}
      <button onClick={() => setOpen(!open)} className={`w-14 h-14 md:w-16 md:h-16 rounded-[1.2rem] shadow-2xl flex items-center justify-center transition-all duration-300 ${open ? 'bg-slate-800 rotate-45' : 'bg-blue-600'}`}>
        <Plus size={32} className="text-white" />
      </button>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { supabase } from '../services/supabase';
import { Mail, Sparkles, Loader2, ArrowRight, Wallet, UserCheck } from 'lucide-react';

interface LoginProps {
  onGuestLogin: () => void;
}

const Login: React.FC<LoginProps> = ({ onGuestLogin }) => {
  const [email, setEmail] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setMessage(null);

    const { error } = await supabase.auth.signInWithOtp({
      email,
      options: {
        emailRedirectTo: window.location.origin,
      },
    });

    if (error) {
      setMessage({ type: 'error', text: 'Error: ' + error.message });
    } else {
      setMessage({ type: 'success', text: '¡Enlace enviado! Revisa tu email para entrar.' });
    }
    setIsLoading(false);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-950 p-6">
      <div className="w-full max-w-md bg-white dark:bg-slate-900 rounded-[3rem] p-10 shadow-2xl border border-slate-100 dark:border-slate-800 text-center animate-in fade-in zoom-in duration-500">
        <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center text-white mx-auto mb-8 shadow-xl shadow-blue-200 dark:shadow-none">
          <Wallet size={40} />
        </div>

        <h1 className="text-3xl font-black text-slate-900 dark:text-white mb-2 tracking-tight">Finanzas Pro <span className="text-blue-600">AI</span></h1>
        <p className="text-slate-500 dark:text-slate-400 font-medium mb-10">Tu estrategia financiera sincronizada en todos tus dispositivos.</p>

        <form onSubmit={handleLogin} className="space-y-4">
          <div className="relative">
            <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input 
              type="email" 
              placeholder="tu@email.com" 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl py-4 pl-12 pr-4 font-bold outline-none focus:border-blue-500 transition-all dark:text-white"
              required
            />
          </div>

          <button 
            type="submit" 
            disabled={isLoading}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl flex items-center justify-center gap-2 transition-all shadow-xl shadow-blue-100 dark:shadow-none active:scale-95 disabled:opacity-50"
          >
            {isLoading ? <Loader2 size={20} className="animate-spin" /> : <>Entrar con Magic Link <ArrowRight size={20} /></>}
          </button>
        </form>

        <div className="relative my-8">
          <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-slate-100 dark:border-slate-800"></div></div>
          <div className="relative flex justify-center text-[10px] uppercase font-black tracking-widest text-slate-400 dark:text-slate-600"><span className="bg-white dark:bg-slate-900 px-4">o también</span></div>
        </div>

        <button 
          onClick={onGuestLogin}
          className="w-full bg-slate-50 dark:bg-slate-800 hover:bg-slate-100 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300 font-bold py-4 rounded-2xl flex items-center justify-center gap-2 transition-all border border-slate-100 dark:border-slate-700 active:scale-95"
        >
          <UserCheck size={20} /> Acceso de Invitado (Modo Local)
        </button>

        {message && (
          <div className={`mt-6 p-4 rounded-xl text-sm font-bold animate-in slide-in-from-top-2 ${message.type === 'success' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-rose-50 text-rose-600 border border-rose-100'}`}>
            {message.text}
          </div>
        )}

        <div className="mt-8 p-4 bg-blue-50/50 dark:bg-blue-900/10 rounded-2xl border border-blue-100/50 dark:border-blue-900/30">
          <p className="text-[10px] text-blue-600 dark:text-blue-400 font-bold text-center leading-relaxed">
            Si el enlace del correo no funciona en este entorno, utiliza el <strong>Modo Invitado</strong> para probar Aura Vision y el Asesor IA.
          </p>
        </div>

        <p className="mt-8 text-[10px] text-slate-400 font-black uppercase tracking-widest flex items-center justify-center gap-2">
          <Sparkles size={12} /> Powered by Supabase & Gemini
        </p>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../App';
import { 
  Plus, 
  Edit2, 
  Trash2, 
  ShoppingBag, 
  ChevronRight, 
  X, 
  ArrowLeftRight,
  TrendingDown,
  TrendingUp,
  AlertCircle,
  Tag,
  ChevronDown,
  History,
  Palette
} from 'lucide-react';
import { Budget } from '../types';
import { CATEGORIES, INCOME_CATEGORIES, ICON_MAP, BUDGET_PRESET_COLORS } from '../constants';

const BudgetManager: React.FC = () => {
  const { budgets, transactions, currentDate, updateBudget, addBudget, deleteBudget, theme } = useFinance();

  // UI States
  const [activeTab, setActiveTab] = useState<'expense' | 'income'>('expense');
  const [selectedBudget, setSelectedBudget] = useState<Budget | null>(null);
  const [isEditing, setIsEditing] = useState<Budget | null>(null);
  const [isCreating, setIsCreating] = useState(false);

  // Form States
  const [category, setCategory] = useState('');
  const [limit, setLimit] = useState<number | ''>('');
  const [customCategory, setCustomCategory] = useState('');
  const [isCustomMode, setIsCustomMode] = useState(false);
  const [selectedIcon, setSelectedIcon] = useState('ShoppingBag');
  const [selectedColor, setSelectedColor] = useState('#3b82f6');

  // Cálculo dinámico de presupuestos con su gasto real
  const budgetsWithCalculatedSpent = useMemo(() => {
    return budgets.map(b => {
      const calculatedSpent = transactions
        .filter(t => t.date.startsWith(currentDate) && t.category === b.category)
        .reduce((sum, t) => {
          if (b.type === 'expense') {
            if (t.type === 'expense') return sum + t.amount;
            if (t.type === 'income' && t.refundId) return sum - t.amount;
          }
          if (b.type === 'income' && t.type === 'income') return sum + t.amount;
          return sum;
        }, 0);

      return { ...b, spent: calculatedSpent };
    });
  }, [budgets, transactions, currentDate]);

  const filteredBudgets = useMemo(() => {
    return budgetsWithCalculatedSpent.filter(b => b.type === activeTab);
  }, [budgetsWithCalculatedSpent, activeTab]);

  const budgetTransactions = useMemo(() => {
    if (!selectedBudget) return [];
    return transactions.filter(t => 
      t.category === selectedBudget.category && 
      t.date.startsWith(currentDate)
    ).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [selectedBudget, transactions, currentDate]);

  const totals = useMemo(() => {
    const b = budgetsWithCalculatedSpent.filter(x => x.type === activeTab);
    return {
      limit: b.reduce((s, x) => s + x.limit, 0),
      actual: b.reduce((s, x) => s + x.spent, 0)
    };
  }, [budgetsWithCalculatedSpent, activeTab]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const finalCategory = isCustomMode ? customCategory : category;
    if (!finalCategory || limit === '') return;

    if (isEditing) {
      updateBudget({ ...isEditing, category: finalCategory, limit: Number(limit), icon: selectedIcon, color: selectedColor });
      setIsEditing(null);
    } else {
      addBudget({ 
        category: finalCategory, 
        limit: Number(limit), 
        type: activeTab,
        icon: selectedIcon,
        color: selectedColor
      });
      setIsCreating(false);
    }
    resetForm();
  };

  const resetForm = () => {
    setCategory('');
    setLimit('');
    setCustomCategory('');
    setIsCustomMode(false);
    setSelectedIcon('ShoppingBag');
    setSelectedColor('#3b82f6');
  };

  const openCreate = () => {
    resetForm();
    const defaultCats = activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
    setCategory(defaultCats[0].name);
    setSelectedIcon(defaultCats[0].icon);
    setSelectedColor(defaultCats[0].color);
    setIsCreating(true);
  };

  const openEdit = (b: Budget) => {
    const defaultCats = b.type === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
    const isStandard = defaultCats.some(c => c.name === b.category);

    setCategory(isStandard ? b.category : 'Otra');
    setCustomCategory(isStandard ? '' : b.category);
    setIsCustomMode(!isStandard);
    setLimit(b.limit);
    setSelectedIcon(b.icon);
    setSelectedColor(b.color || '#3b82f6');
    setIsEditing(b);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Presupuestos</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight transition-colors">Controla tus finanzas de {currentDate} con precisión.</p>
        </div>
        <button 
          onClick={openCreate}
          className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95"
        >
          <Plus size={20} />
          Nuevo Límite
        </button>
      </div>

      <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1.5 rounded-3xl w-full md:w-fit border border-slate-200 dark:border-slate-700 shadow-inner">
        <button 
          onClick={() => setActiveTab('expense')} 
          className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-3 text-xs font-black rounded-2xl transition-all ${activeTab === 'expense' ? 'bg-white dark:bg-slate-700 text-rose-600 dark:text-rose-400 shadow-md' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
        >
          <TrendingDown size={16} /> GASTOS
        </button>
        <button 
          onClick={() => setActiveTab('income')} 
          className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-3 text-xs font-black rounded-2xl transition-all ${activeTab === 'income' ? 'bg-white dark:bg-slate-700 text-emerald-600 dark:text-emerald-400 shadow-md' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
        >
          <TrendingUp size={16} /> INGRESOS
        </button>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div className={`p-6 rounded-[2.5rem] border shadow-sm flex items-center gap-4 bg-white dark:bg-slate-900 border-slate-100 dark:border-slate-800 transition-colors`}>
          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${activeTab === 'expense' ? 'bg-rose-50 dark:bg-rose-900/40 text-rose-500 dark:text-rose-400' : 'bg-emerald-50 dark:bg-emerald-900/40 text-emerald-500 dark:text-emerald-400'}`}>
            <ShoppingBag size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Total {activeTab === 'expense' ? 'Presupuestado' : 'Objetivo'}</p>
            <p className="text-2xl font-black text-slate-800 dark:text-white transition-colors">{totals.limit.toLocaleString()}€</p>
          </div>
        </div>
        <div className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm flex items-center gap-4 transition-colors">
          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400`}>
            <ArrowLeftRight size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{activeTab === 'expense' ? 'Consumo Real' : 'Ingreso Real'}</p>
            <p className="text-2xl font-black text-blue-600 dark:text-blue-400 transition-colors">{totals.actual.toLocaleString()}€</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {filteredBudgets.map(b => {
          const progress = b.limit > 0 ? Math.min((b.spent / b.limit) * 100, 100) : 0;
          const isOverBudget = activeTab === 'expense' && b.spent > b.limit;

          return (
            <div 
              key={b.id} 
              onClick={() => setSelectedBudget(b)}
              className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-slate-100 dark:border-slate-800 shadow-sm hover:shadow-md transition-all group cursor-pointer active:scale-[0.99] duration-300"
            >
              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-4">
                  <div 
                    className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-inner dark:shadow-none transition-colors`}
                    style={{ backgroundColor: `${b.color}${theme === 'dark' ? '30' : '15'}`, color: b.color }}
                  >
                    {ICON_MAP[b.icon] || <Tag size={24} />}
                  </div>
                  <div>
                    <h4 className="text-lg font-black text-slate-800 dark:text-white tracking-tight transition-colors">{b.category}</h4>
                    <p className="text-xs text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">{activeTab === 'expense' ? 'Gasto' : 'Ingreso'}</p>
                  </div>
                </div>
                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                  <button onClick={(e) => { e.stopPropagation(); openEdit(b); }} className="p-2.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/40 rounded-xl transition-colors"><Edit2 size={18} /></button>
                  <button onClick={(e) => { e.stopPropagation(); if(confirm('¿Seguro que quieres eliminar este presupuesto?')) deleteBudget(b.id); }} className="p-2.5 text-slate-400 hover:text-rose-600 hover:bg-rose-50 dark:hover:bg-rose-900/40 rounded-xl transition-colors"><Trash2 size={18} /></button>
                </div>
              </div>

              <div className="space-y-5">
                <div className="flex justify-between items-end">
                   <div>
                      <p className={`text-4xl font-black tracking-tight ${isOverBudget ? 'text-rose-500 dark:text-rose-400' : 'text-slate-900 dark:text-white'} transition-colors`}>{b.spent.toLocaleString('es-ES')}€</p>
                      <p className="text-[10px] text-slate-400 dark:text-slate-500 font-black uppercase tracking-widest transition-colors">de {b.limit.toLocaleString()}€ {activeTab === 'expense' ? 'definidos' : 'objetivo'}</p>
                   </div>
                   <div className="text-right">
                      <span 
                        style={!isOverBudget ? { backgroundColor: `${b.color}${theme === 'dark' ? '30' : '15'}`, color: b.color } : {}}
                        className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-wider transition-colors ${isOverBudget ? 'bg-rose-50 dark:bg-rose-900/40 text-rose-500 dark:text-rose-400' : ''}`}
                      >
                        {activeTab === 'expense' ? (isOverBudget ? 'Excedido' : progress > 85 ? 'Cuidado' : 'Correcto') : (b.spent >= b.limit ? 'Logrado' : 'En progreso')}
                      </span>
                   </div>
                </div>
                <div className="w-full bg-slate-100 dark:bg-slate-800 h-3 rounded-full overflow-hidden transition-colors">
                  <div 
                    className={`h-full rounded-full transition-all duration-1000 ease-out`} 
                    style={{ 
                      width: `${progress}%`,
                      backgroundColor: isOverBudget ? (theme === 'dark' ? '#f43f5e' : '#f43f5e') : b.color 
                    }}
                  ></div>
                </div>
                <div className="flex items-center justify-between">
                   <p className="text-xs text-slate-400 dark:text-slate-500 font-bold flex items-center gap-1 transition-colors"><ChevronRight size={14} style={{ color: b.color }} /> Ver detalles</p>
                   {activeTab === 'expense' && b.limit > b.spent && (
                     <p className="text-xs font-black text-slate-700 dark:text-slate-300 transition-colors">Dispones de {(b.limit - b.spent).toLocaleString()}€ más</p>
                   )}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Modal Ver Detalles */}
      {selectedBudget && (
        <div className="fixed inset-0 bg-slate-900/80 dark:bg-black/90 backdrop-blur-xl z-[60] flex items-center justify-center p-4" onClick={() => setSelectedBudget(null)}>
          <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-lg p-8 md:p-10 shadow-2xl animate-in fade-in zoom-in duration-300 border border-slate-100 dark:border-slate-800 overflow-hidden flex flex-col max-h-[85vh]" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-start mb-8 flex-shrink-0">
               <div className="flex items-center gap-5">
                  <div 
                    className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center shadow-lg dark:shadow-none transition-colors`}
                    style={{ backgroundColor: `${selectedBudget.color}${theme === 'dark' ? '30' : '15'}`, color: selectedBudget.color }}
                  >
                    {React.cloneElement(ICON_MAP[selectedBudget.icon] as React.ReactElement<{size: number}>, { size: 28 })}
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">{selectedBudget.category}</h3>
                    <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Movimientos de {currentDate}</p>
                  </div>
               </div>
               <button onClick={() => setSelectedBudget(null)} className="p-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400"><X size={24} /></button>
            </div>

            <div className="bg-slate-50 dark:bg-slate-800/50 rounded-3xl p-6 mb-8 border border-slate-100 dark:border-slate-800 flex-shrink-0 transition-colors">
               <div className="flex justify-between items-end mb-4">
                  <div>
                    <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase mb-1">Total acumulado</p>
                    <p className="text-3xl font-black text-slate-900 dark:text-white transition-colors">{selectedBudget.spent.toLocaleString()}€</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase mb-1">Límite</p>
                    <p className="text-lg font-bold text-slate-600 dark:text-slate-400 transition-colors">{selectedBudget.limit.toLocaleString()}€</p>
                  </div>
               </div>
               <div className="w-full h-3 bg-white dark:bg-slate-800 rounded-full overflow-hidden border border-slate-200 dark:border-slate-700">
                  <div 
                    className={`h-full rounded-full transition-all duration-1000`} 
                    style={{ 
                      width: `${Math.min((selectedBudget.spent / selectedBudget.limit) * 100, 100)}%`,
                      backgroundColor: (selectedBudget.type === 'expense' && selectedBudget.spent > selectedBudget.limit) ? '#f43f5e' : selectedBudget.color 
                    }}
                  ></div>
               </div>
            </div>

            <div className="flex items-center gap-2 mb-4 flex-shrink-0">
              <History size={16} className="text-slate-400 dark:text-slate-600" />
              <h4 className="text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest">Historial Reciente</h4>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-3 pr-2">
              {budgetTransactions.length > 0 ? budgetTransactions.map(tx => (
                <div key={tx.id} className="flex justify-between items-center p-4 bg-white dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800 rounded-2xl hover:border-blue-200 dark:hover:border-blue-800 transition-colors duration-300">
                  <div className="flex items-center gap-4">
                    <div className="text-center bg-slate-50 dark:bg-slate-900 w-10 py-1.5 rounded-xl border border-slate-100 dark:border-slate-700 transition-colors">
                      <p className="text-[8px] font-black text-slate-400 dark:text-slate-600 uppercase">{new Date(tx.date).toLocaleDateString('es-ES', { month: 'short' })}</p>
                      <p className="text-xs font-black text-slate-700 dark:text-slate-300 transition-colors">{new Date(tx.date).getDate()}</p>
                    </div>
                    <div>
                      <p className="text-sm font-bold text-slate-800 dark:text-slate-200 line-clamp-1 transition-colors">{tx.description}</p>
                      <p className="text-[10px] font-medium text-slate-400 dark:text-slate-500">Manual</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className={`font-black ${tx.type === 'income' ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-900 dark:text-white'} transition-colors`}>
                      {tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€
                    </p>
                  </div>
                </div>
              )) : (
                <div className="text-center py-12 bg-slate-50 dark:bg-slate-800/30 rounded-[2rem] border-2 border-dashed border-slate-200 dark:border-slate-700 transition-colors">
                  <AlertCircle size={32} className="mx-auto text-slate-300 dark:text-slate-700 mb-3" />
                  <p className="text-xs font-bold text-slate-400 dark:text-slate-600 uppercase tracking-widest">No hay transacciones aún</p>
                </div>
              )}
            </div>

            <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 flex-shrink-0">
               <button onClick={() => setSelectedBudget(null)} className="w-full py-4 bg-slate-900 dark:bg-blue-600 text-white font-black rounded-2xl hover:bg-slate-800 dark:hover:bg-blue-700 transition-all active:scale-[0.98]">ENTENDIDO</button>
            </div>
          </div>
        </div>
      )}

      {(isCreating || isEditing) && (
        <div className="fixed inset-0 bg-slate-900/80 dark:bg-black/90 backdrop-blur-xl z-[60] flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[3.5rem] w-full max-w-md p-10 md:p-14 shadow-2xl animate-in fade-in zoom-in duration-300 border border-slate-100 dark:border-slate-800 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-3xl font-black text-slate-900 dark:text-white tracking-tight">{isEditing ? 'Editar Límite' : 'Nueva Categoría'}</h3>
              <button onClick={() => { setIsCreating(false); setIsEditing(null); }} className="p-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400 transition-colors"><X size={24} /></button>
            </div>

            <form onSubmit={handleSave} className="space-y-8">
              <div className="space-y-4">
                <label className="block text-[11px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest pl-1">Seleccionar Icono</label>
                <div className="grid grid-cols-6 gap-2 bg-slate-50 dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700 max-h-48 overflow-y-auto custom-scrollbar transition-colors">
                  {Object.keys(ICON_MAP).map(iconName => (
                    <button 
                      key={iconName} 
                      type="button" 
                      onClick={() => setSelectedIcon(iconName)}
                      className={`p-2 rounded-xl transition-all ${selectedIcon === iconName ? 'bg-blue-600 text-white shadow-md' : 'bg-white dark:bg-slate-700 text-slate-400 dark:text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-600'}`}
                    >
                      {ICON_MAP[iconName]}
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <label className="block text-[11px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest pl-1">Personalizar Color</label>
                  <div className="flex items-center gap-2">
                    <input 
                      type="color" 
                      value={selectedColor} 
                      onChange={e => setSelectedColor(e.target.value)}
                      className="w-10 h-10 border-0 bg-transparent cursor-pointer rounded-full overflow-hidden shadow-sm transition-transform hover:scale-105"
                    />
                    <Palette size={16} className="text-slate-400 dark:text-slate-600" />
                  </div>
                </div>
                <div className="flex flex-wrap gap-2">
                  {BUDGET_PRESET_COLORS.map(c => (
                    <button 
                      key={c}
                      type="button"
                      onClick={() => setSelectedColor(c)}
                      className={`w-8 h-8 rounded-full border-2 transition-transform hover:scale-110 ${selectedColor === c ? 'border-slate-900 dark:border-white scale-110' : 'border-transparent'}`}
                      style={{ backgroundColor: c }}
                    />
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <label className="block text-[11px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest pl-1">Categoría</label>
                <div className="relative">
                  <select 
                    value={category} 
                    onChange={e => {
                      setCategory(e.target.value);
                      const isAnother = e.target.value === 'Otra';
                      setIsCustomMode(isAnother);
                      if(!isAnother) {
                        const defaultList = activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
                        const match = defaultList.find(c => c.name === e.target.value);
                        if(match) {
                          setSelectedIcon(match.icon);
                          setSelectedColor(match.color);
                        }
                      }
                    }}
                    className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-black text-slate-800 dark:text-white focus:bg-white dark:focus:bg-slate-900 focus:border-blue-400 dark:focus:border-blue-600 outline-none transition-all appearance-none cursor-pointer"
                    required
                  >
                    {(activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES).map(c => (
                      <option key={c.name} value={c.name} className="dark:bg-slate-900">{c.name}</option>
                    ))}
                    <option value="Otra" className="dark:bg-slate-900">-- Personalizada --</option>
                  </select>
                  <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 dark:text-slate-600 pointer-events-none" size={20} />
                </div>
                {isCustomMode && (
                  <input type="text" placeholder="Nombre de categoría..." className="w-full bg-blue-50 dark:bg-blue-900/20 border-2 border-blue-100 dark:border-blue-900 rounded-2xl p-5 font-black text-blue-900 dark:text-blue-300 outline-none animate-in slide-in-from-top-2" value={customCategory} onChange={e => setCustomCategory(e.target.value)} required />
                )}
              </div>

              <div className="space-y-4">
                <label className="block text-[11px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest pl-1">Importe Mensual (€)</label>
                <input type="number" value={limit} onChange={e => setLimit(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-6 text-center text-4xl font-black text-slate-900 dark:text-white outline-none" placeholder="0" required />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => { setIsCreating(false); setIsEditing(null); }} className="flex-1 py-5 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-black rounded-2xl transition-colors">CANCELAR</button>
                <button type="submit" className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100 dark:shadow-none flex items-center justify-center gap-2 transition-all active:scale-[0.98]">{isEditing ? <Edit2 size={18}/> : <Plus size={18}/>}{isEditing ? 'GUARDAR' : 'CREAR'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default BudgetManager;

import React, { useState, useEffect, useMemo, createContext, useContext } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, useNavigate } from 'react-router-dom';
import { 
  LayoutDashboard, Wallet, PiggyBank, Receipt, BarChart3, 
  MessageSquare, Menu, X, Plus, Camera, CalendarDays, 
  CalendarRange, Sun, Moon, LineChart as LineChartIcon, 
  LogOut, Loader2, Sparkles, CloudCheck, CloudUpload, RefreshCw
} from 'lucide-react';
import { FinanceState, Account, Saving, Refund, Transaction, Budget, AIChallenge } from './types';
import { INITIAL_DATA } from './constants';
import { supabase } from './services/supabase';

// Componentes de vistas
import Dashboard from './components/Dashboard.tsx';
import Accounts from './components/Accounts.tsx';
import Savings from './components/Savings.tsx';
import Refunds from './components/Refunds.tsx';
import Transactions from './components/Transactions.tsx';
import BudgetManager from './components/Budget.tsx';
import AIAdvisor from './components/AIAdvisor.tsx';
import WealthProjections from './components/WealthProjections.tsx';
import Login from './components/Login.tsx';

interface FinanceContextType extends FinanceState {
  getAccountHistoricalBalance: (accountId: string, dateStr: string) => number;
  getSavingHistoricalBalance: (savingId: string, dateStr: string) => number;
  addTransaction: (t: Omit<Transaction, 'id'>, myPart?: number) => void;
  updateTransaction: (t: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addAccount: (a: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (a: Account) => void;
  deleteAccount: (id: string) => void;
  addSaving: (s: Omit<Saving, 'id'>) => void;
  updateSaving: (s: Saving) => void;
  deleteSaving: (id: string) => void;
  addRefund: (r: Omit<Refund, 'id'>) => void;
  updateRefund: (r: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addBudget: (b: Omit<Budget, 'id' | 'spent' | 'icon' | 'type'> & { type?: 'income' | 'expense'; icon?: string }) => void;
  updateBudget: (b: Budget) => void;
  deleteBudget: (id: string) => void;
  changePeriod: (offset: number) => void;
  setPeriod: (date: string) => void;
  setViewMode: (mode: 'month' | 'year') => void;
  updateLayout: (newLayout: string[]) => void;
  setChallenges: (challenges: AIChallenge[]) => void;
  toggleTheme: () => void;
  isGuest: boolean;
  isSyncing: boolean;
  syncError: boolean;
  loginAsGuest: () => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);
export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [state, setState] = useState<FinanceState>(INITIAL_DATA as any);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState(false);
  const [dataLoadedFromCloud, setDataLoadedFromCloud] = useState(false);

  // 1. Manejo de Sesión Inicial
  useEffect(() => {
    const checkInitialSession = async () => {
      const { data: { session } } = await supabase.auth.getSession();

      const guestFlag = localStorage.getItem('finanzas_pro_guest') === 'true';

      if (session) {
        setSession(session);
        setIsGuest(false);
        await fetchUserData(session.user.id);
      } else if (guestFlag) {
        setIsGuest(true);
        const savedState = localStorage.getItem('finanzas_pro_local_state');
        if (savedState) setState(JSON.parse(savedState));
        setIsLoading(false);
      } else {
        setIsLoading(false);
      }
    };

    checkInitialSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (session) {
        setSession(session);
        setIsGuest(false);
        await fetchUserData(session.user.id);
      } else {
        if (localStorage.getItem('finanzas_pro_guest') !== 'true') {
          setSession(null);
          setIsGuest(false);
          setState(INITIAL_DATA as any);
          setDataLoadedFromCloud(false);
        }
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  // 2. Cargar datos de la nube
  const fetchUserData = async (userId: string) => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('state')
        .eq('id', userId)
        .single();

      if (data && data.state) {
        setState(data.state);
        setDataLoadedFromCloud(true);
      } else if (error && error.code === 'PGRST116') {
        // Usuario nuevo, crear perfil con datos iniciales
        await supabase.from('profiles').upsert({ id: userId, state: INITIAL_DATA });
        setState(INITIAL_DATA as any);
        setDataLoadedFromCloud(true);
      }
    } catch (err) {
      console.error("Error fetching user data:", err);
    } finally {
      setIsLoading(false);
    }
  };

  // 3. Persistencia Automática (Debounced)
  useEffect(() => {
    if (!isLoading) {
      if (session && dataLoadedFromCloud) {
        setSyncError(false);
        const timer = setTimeout(async () => {
          setIsSyncing(true);
          const { error } = await supabase
            .from('profiles')
            .upsert({ id: session.user.id, state, updated_at: new Date().toISOString() });

          if (error) {
            console.error("Error syncing to cloud:", error);
            setSyncError(true);
          }
          setIsSyncing(false);
        }, 1500); // 1.5s de debounce para no saturar la API
        return () => clearTimeout(timer);
      } else if (isGuest) {
        localStorage.setItem('finanzas_pro_local_state', JSON.stringify(state));
      }
    }
  }, [state, session, isGuest, isLoading, dataLoadedFromCloud]);

  // Manejo de Temas
  useEffect(() => {
    if (state.theme === 'dark') document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [state.theme]);

  const getAccountHistoricalBalance = (accountId: string, dateLimit: string) => {
    const account = state.accounts.find(a => a.id === accountId);
    if (!account) return 0;
    let endDay = dateLimit.length === 4 ? `${dateLimit}-12-31` : `${dateLimit}-31`; 
    const relevantTransactions = state.transactions.filter(t => t.accountId === accountId && t.date <= endDay);
    return relevantTransactions.reduce((acc, t) => acc + (t.type === 'income' ? t.amount : -t.amount), account.initialBalance);
  };

  const getSavingHistoricalBalance = (savingId: string, dateLimit: string) => {
    const relevant = state.transactions.filter(t => t.savingId === savingId && t.date <= (dateLimit.length === 4 ? `${dateLimit}-12-31` : `${dateLimit}-31`));
    return relevant.reduce((acc, t) => acc + t.amount, 0);
  };

  const loginAsGuest = () => {
    localStorage.setItem('finanzas_pro_guest', 'true');
    setIsGuest(true);
    const saved = localStorage.getItem('finanzas_pro_local_state');
    if (saved) setState(JSON.parse(saved));
    else setState(INITIAL_DATA as any);
  };

  const logout = () => {
    localStorage.removeItem('finanzas_pro_guest');
    localStorage.removeItem('finanzas_pro_local_state');
    setIsGuest(false);
    setSession(null);
    setDataLoadedFromCloud(false);
    supabase.auth.signOut();
  };

  if (isLoading) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950">
        <Loader2 className="animate-spin text-blue-600 mb-4" size={48} />
        <p className="text-slate-400 font-black uppercase tracking-widest text-[10px]">Sincronizando con tu bóveda...</p>
      </div>
    );
  }

  if (!session && !isGuest) {
    return <Login onGuestLogin={loginAsGuest} />;
  }

  const contextValue: FinanceContextType = {
    ...state,
    getAccountHistoricalBalance,
    getSavingHistoricalBalance,
    isGuest,
    isSyncing,
    syncError,
    loginAsGuest,
    addTransaction: (t, myPart) => {
      const id = 'tx_' + Math.random().toString(36).substr(2, 9);
      let finalTx = { ...t, id };
      let newRefunds = [...state.refunds];
      if (t.type === 'expense' && t.isRefund) {
        const refundId = 'ref_' + Date.now();
        const partToPay = myPart !== undefined ? myPart : t.amount / 2;
        newRefunds.push({ id: refundId, name: t.description, totalAmount: t.amount, paidByMe: partToPay, pendingAmount: t.amount - partToPay, status: 'open', notes: 'Auto', date: t.date, category: t.category, originTransactionId: id });
        finalTx.refundId = refundId;
      }
      setState(prev => ({ ...prev, transactions: [finalTx as Transaction, ...prev.transactions], refunds: newRefunds }));
    },
    updateTransaction: (updatedTx) => setState(prev => ({ ...prev, transactions: prev.transactions.map(t => t.id === updatedTx.id ? updatedTx : t) })),
    deleteTransaction: (id) => setState(prev => ({ ...prev, transactions: prev.transactions.filter(tx => tx.id !== id) })),
    addAccount: (a) => setState(prev => ({ ...prev, accounts: [...prev.accounts, { ...a, id: 'acc_' + Date.now(), currentBalance: a.initialBalance } as Account] })),
    updateAccount: (a) => setState(prev => ({ ...prev, accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc) })),
    deleteAccount: (id) => setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) })),
    addSaving: (s) => setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id: 'sav_' + Date.now() } as Saving] })),
    updateSaving: (s) => setState(prev => ({ ...prev, savings: prev.savings.map(sv => sv.id === s.id ? s : sv) })),
    deleteSaving: (id) => setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) })),
    addRefund: (r) => setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id: 'ref_' + Date.now() } as Refund] })),
    updateRefund: (r) => setState(prev => ({ ...prev, refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf) })),
    deleteRefund: (id) => setState(prev => ({ ...prev, refunds: prev.refunds.filter(r => r.id !== id) })),
    mergeRefunds: (id1, id2) => {
      const r1 = state.refunds.find(r => r.id === id1);
      const r2 = state.refunds.find(r => r.id === id2);
      if (!r1 || !r2) return;
      const merged: Refund = {
        id: 'ref_' + Date.now(),
        name: `${r1.name} + ${r2.name}`,
        totalAmount: r1.totalAmount + r2.totalAmount,
        paidByMe: r1.paidByMe + r2.paidByMe,
        pendingAmount: r1.pendingAmount + r2.pendingAmount,
        status: (r1.status === 'open' || r2.status === 'open') ? 'open' : 'closed',
        notes: `Fusionado: ${r1.notes} | ${r2.notes}`,
        date: new Date().toISOString(),
        category: r1.category
      };
      setState(prev => ({
        ...prev,
        refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), merged]
      }));
    },
    addBudget: (b) => setState(prev => ({ ...prev, budgets: [...prev.budgets, { ...b, id: 'budget_' + Date.now(), spent: 0 } as Budget] })),
    updateBudget: (b) => setState(prev => ({ ...prev, budgets: prev.budgets.map(bg => bg.id === b.id ? b : bg) })),
    deleteBudget: (id) => setState(prev => ({ ...prev, budgets: prev.budgets.filter(b => b.id !== id) })),
    changePeriod: (offset) => {
      const [year, month] = state.currentDate.split('-').map(Number);
      const newDate = new Date(year, (month || 1) - 1 + offset, 1);
      const newDateStr = state.viewMode === 'year' ? newDate.getFullYear().toString() : `${newDate.getFullYear()}-${String(newDate.getMonth() + 1).padStart(2, '0')}`;
      setState(prev => ({ ...prev, currentDate: newDateStr }));
    },
    setPeriod: (dateStr) => setState(prev => ({ ...prev, currentDate: dateStr })),
    setViewMode: (mode) => setState(prev => ({ ...prev, viewMode: mode })),
    updateLayout: (newLayout) => setState(prev => ({ ...prev, dashboardLayout: newLayout })),
    setChallenges: (challenges) => setState(prev => ({ ...prev, challenges })),
    toggleTheme: () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }))
  };

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 overflow-hidden text-slate-900 dark:text-slate-100">
          <Sidebar isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} onLogout={logout} isGuest={isGuest} session={session} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={() => setIsMenuOpen(true)} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/wealth" element={<WealthProjections />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

