            <div className="w-8 h-8 bg-blue-600 dark:bg-blue-500 rounded-lg flex items-center justify-center text-white"><Wallet size={18} /></div>
            Finanzas Pro
          </h1>
          <button onClick={onClose} className="md:hidden p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"><X size={20} /></button>
        </div>

        <div className="mx-4 mb-4 p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-800 flex items-center gap-3">
             {isGuest ? (
               <Sparkles className="text-amber-500" size={16} />
             ) : (
               <div className="w-8 h-8 rounded-full bg-blue-100 dark:bg-blue-900/40 flex items-center justify-center text-blue-600 dark:text-blue-400 font-black text-[10px]">
                 {session?.user?.email?.substring(0,2).toUpperCase()}
               </div>
             )}
             <div className="flex-1 overflow-hidden">
               <p className="text-[10px] font-black text-slate-600 dark:text-slate-300 uppercase tracking-widest truncate">
                 {isGuest ? 'Modo Invitado' : session?.user?.email}
               </p>
               <div className="flex items-center gap-1.5 mt-0.5">
                 {isGuest ? (
                   <p className="text-[8px] text-amber-500 font-medium">Solo este dispositivo</p>
                 ) : isSyncing ? (
                   <><RefreshCw size={8} className="animate-spin text-blue-500" /><p className="text-[8px] text-blue-500 font-bold uppercase">Sincronizando...</p></>
                 ) : syncError ? (
                   <p className="text-[8px] text-rose-500 font-bold uppercase">Error de red</p>
                 ) : (
                   <><CloudCheck size={10} className="text-emerald-500" /><p className="text-[8px] text-emerald-500 font-bold uppercase">En la nube</p></>
                 )}
               </div>
             </div>
