import React, { useState, useEffect, useMemo, createContext, useContext } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, useNavigate } from 'react-router-dom';
import { 
  LayoutDashboard, Wallet, PiggyBank, Receipt, BarChart3, 
  MessageSquare, Menu, X, Plus, Camera, CalendarDays, 
  CalendarRange, Sun, Moon, LineChart as LineChartIcon, 
  LogOut, Loader2, Sparkles, CloudCheck, CloudUpload, RefreshCw,
  ChevronLeft, ChevronRight
} from 'lucide-react';
import { FinanceState, Account, Saving, Refund, Transaction, Budget, AIChallenge } from './types';
import { INITIAL_DATA } from './constants';
import { supabase } from './services/supabase';

// Componentes de vistas
import Dashboard from './components/Dashboard.tsx';
import Accounts from './components/Accounts.tsx';
import Savings from './components/Savings.tsx';
import Refunds from './components/Refunds.tsx';
import Transactions from './components/Transactions.tsx';
import BudgetManager from './components/Budget.tsx';
import AIAdvisor from './components/AIAdvisor.tsx';
import WealthProjections from './components/WealthProjections.tsx';
import Login from './components/Login.tsx';

interface FinanceContextType extends FinanceState {
  getAccountHistoricalBalance: (accountId: string, dateStr: string) => number;
  getSavingHistoricalBalance: (savingId: string, dateStr: string) => number;
  addTransaction: (t: Omit<Transaction, 'id'>, myPart?: number) => void;
  updateTransaction: (t: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addAccount: (a: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (a: Account) => void;
  deleteAccount: (id: string) => void;
  addSaving: (s: Omit<Saving, 'id'>) => void;
  updateSaving: (s: Saving) => void;
  deleteSaving: (id: string) => void;
  addRefund: (r: Omit<Refund, 'id'>) => void;
  updateRefund: (r: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addBudget: (b: Omit<Budget, 'id' | 'spent' | 'icon' | 'type'> & { type?: 'income' | 'expense'; icon?: string }) => void;
  updateBudget: (b: Budget) => void;
  deleteBudget: (id: string) => void;
  changePeriod: (offset: number) => void;
  setPeriod: (date: string) => void;
  setViewMode: (mode: 'month' | 'year') => void;
  updateLayout: (newLayout: string[]) => void;
  setChallenges: (challenges: AIChallenge[]) => void;
  toggleTheme: () => void;
  isGuest: boolean;
  isSyncing: boolean;
  syncError: boolean;
  loginAsGuest: () => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);
export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [state, setState] = useState<FinanceState>(INITIAL_DATA as any);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState(false);
  const [dataLoadedFromCloud, setDataLoadedFromCloud] = useState(false);

  // 1. Manejo de Sesión Inicial
  useEffect(() => {
    const checkInitialSession = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      const guestFlag = localStorage.getItem('finanzas_pro_guest') === 'true';

      if (session) {
        setSession(session);
        setIsGuest(false);
        await fetchUserData(session.user.id);
      } else if (guestFlag) {
        setIsGuest(true);
        const savedState = localStorage.getItem('finanzas_pro_local_state');
        if (savedState) setState(JSON.parse(savedState));
        setIsLoading(false);
      } else {
        setIsLoading(false);
      }
    };

    checkInitialSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (session) {
        setSession(session);
        setIsGuest(false);
        await fetchUserData(session.user.id);
      } else {
        if (localStorage.getItem('finanzas_pro_guest') !== 'true') {
          setSession(null);
          setIsGuest(false);
          setState(INITIAL_DATA as any);
          setDataLoadedFromCloud(false);
        }
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  // 2. Cargar datos de la nube
  const fetchUserData = async (userId: string) => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('state')
        .eq('id', userId)
        .single();

      if (data && data.state) {
        setState(data.state);
        setDataLoadedFromCloud(true);
      } else {
        // Usuario nuevo, crear perfil con datos iniciales
        await supabase.from('profiles').upsert({ id: userId, state: INITIAL_DATA });
        setState(INITIAL_DATA as any);
        setDataLoadedFromCloud(true);
      }
    } catch (err) {
      console.error("Error fetching user data:", err);
    } finally {
      setIsLoading(false);
    }
  };

  // 3. Persistencia Automática
  useEffect(() => {
    if (!isLoading) {
      if (session && dataLoadedFromCloud) {
        setSyncError(false);
        const timer = setTimeout(async () => {
          setIsSyncing(true);
          const { error } = await supabase
            .from('profiles')
            .upsert({ id: session.user.id, state, updated_at: new Date().toISOString() });

          if (error) setSyncError(true);
          setIsSyncing(false);
        }, 1500);
        return () => clearTimeout(timer);
      } else if (isGuest) {
        localStorage.setItem('finanzas_pro_local_state', JSON.stringify(state));
      }
    }
  }, [state, session, isGuest, isLoading, dataLoadedFromCloud]);

  // Temas
  useEffect(() => {
    if (state.theme === 'dark') document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [state.theme]);

  const getAccountHistoricalBalance = (accountId: string, dateLimit: string) => {
    const account = state.accounts.find(a => a.id === accountId);
    if (!account) return 0;
    let endDay = dateLimit.length === 4 ? `${dateLimit}-12-31` : `${dateLimit}-31`; 
    const relevantTransactions = state.transactions.filter(t => t.accountId === accountId && t.date <= endDay);
    return relevantTransactions.reduce((acc, t) => acc + (t.type === 'income' ? t.amount : -t.amount), account.initialBalance);
  };

  const getSavingHistoricalBalance = (savingId: string, dateLimit: string) => {
    const relevant = state.transactions.filter(t => t.savingId === savingId && t.date <= (dateLimit.length === 4 ? `${dateLimit}-12-31` : `${dateLimit}-31`));
    return relevant.reduce((acc, t) => acc + t.amount, 0);
  };

  const loginAsGuest = () => {
    localStorage.setItem('finanzas_pro_guest', 'true');
    setIsGuest(true);
    const saved = localStorage.getItem('finanzas_pro_local_state');
    if (saved) setState(JSON.parse(saved));
    else setState(INITIAL_DATA as any);
  };

  const logout = () => {
    localStorage.removeItem('finanzas_pro_guest');
    localStorage.removeItem('finanzas_pro_local_state');
    setIsGuest(false);
    setSession(null);
    setDataLoadedFromCloud(false);
    supabase.auth.signOut();
  };

  if (isLoading) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950">
        <Loader2 className="animate-spin text-blue-600 mb-4" size={48} />
        <p className="text-slate-400 font-black uppercase tracking-widest text-[10px]">Protegiendo tu capital...</p>
      </div>
    );
  }

  if (!session && !isGuest) {
    return <Login onGuestLogin={loginAsGuest} />;
  }

  const contextValue: FinanceContextType = {
    ...state,
    getAccountHistoricalBalance,
    getSavingHistoricalBalance,
    isGuest,
    isSyncing,
    syncError,
    loginAsGuest,
    addTransaction: (t, myPart) => {
      const id = 'tx_' + Math.random().toString(36).substr(2, 9);
      let finalTx = { ...t, id };
      let newRefunds = [...state.refunds];
      if (t.type === 'expense' && t.isRefund) {
        const refundId = 'ref_' + Date.now();
        const partToPay = myPart !== undefined ? myPart : t.amount / 2;
        newRefunds.push({ id: refundId, name: t.description, totalAmount: t.amount, paidByMe: partToPay, pendingAmount: t.amount - partToPay, status: 'open', notes: 'Auto', date: t.date, category: t.category, originTransactionId: id });
        finalTx.refundId = refundId;
      }
      setState(prev => ({ ...prev, transactions: [finalTx as Transaction, ...prev.transactions], refunds: newRefunds }));
    },
    updateTransaction: (updatedTx) => setState(prev => ({ ...prev, transactions: prev.transactions.map(t => t.id === updatedTx.id ? updatedTx : t) })),
    deleteTransaction: (id) => setState(prev => ({ ...prev, transactions: prev.transactions.filter(tx => tx.id !== id) })),
    addAccount: (a) => setState(prev => ({ ...prev, accounts: [...prev.accounts, { ...a, id: 'acc_' + Date.now(), currentBalance: a.initialBalance } as Account] })),
    updateAccount: (a) => setState(prev => ({ ...prev, accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc) })),
    deleteAccount: (id) => setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) })),
    addSaving: (s) => setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id: 'sav_' + Date.now() } as Saving] })),
    updateSaving: (s) => setState(prev => ({ ...prev, savings: prev.savings.map(sv => sv.id === s.id ? s : sv) })),
    deleteSaving: (id) => setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) })),
    addRefund: (r) => setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id: 'ref_' + Date.now() } as Refund] })),
    updateRefund: (r) => setState(prev => ({ ...prev, refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf) })),
    deleteRefund: (id) => setState(prev => ({ ...prev, refunds: prev.refunds.filter(r => r.id !== id) })),
    mergeRefunds: (id1, id2) => {
      const r1 = state.refunds.find(r => r.id === id1);
      const r2 = state.refunds.find(r => r.id === id2);
      if (!r1 || !r2) return;
      const merged: Refund = {
        id: 'ref_' + Date.now(),
        name: `${r1.name} + ${r2.name}`,
        totalAmount: r1.totalAmount + r2.totalAmount,
        paidByMe: r1.paidByMe + r2.paidByMe,
        pendingAmount: r1.pendingAmount + r2.pendingAmount,
        status: (r1.status === 'open' || r2.status === 'open') ? 'open' : 'closed',
        notes: `Fusionado: ${r1.notes} | ${r2.notes}`,
        date: new Date().toISOString(),
        category: r1.category
      };
      setState(prev => ({
        ...prev,
        refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), merged]
      }));
    },
    addBudget: (b) => setState(prev => ({ ...prev, budgets: [...prev.budgets, { ...b, id: 'budget_' + Date.now(), spent: 0 } as Budget] })),
    updateBudget: (b) => setState(prev => ({ ...prev, budgets: prev.budgets.map(bg => bg.id === b.id ? b : bg) })),
    deleteBudget: (id) => setState(prev => ({ ...prev, budgets: prev.budgets.filter(b => b.id !== id) })),
    changePeriod: (offset) => {
      const [year, month] = state.currentDate.split('-').map(Number);
      const newDate = new Date(year, (month || 1) - 1 + offset, 1);
      const newDateStr = state.viewMode === 'year' ? newDate.getFullYear().toString() : `${newDate.getFullYear()}-${String(newDate.getMonth() + 1).padStart(2, '0')}`;
      setState(prev => ({ ...prev, currentDate: newDateStr }));
    },
    setPeriod: (dateStr) => setState(prev => ({ ...prev, currentDate: dateStr })),
    setViewMode: (mode) => setState(prev => ({ ...prev, viewMode: mode })),
    updateLayout: (newLayout) => setState(prev => ({ ...prev, dashboardLayout: newLayout })),
    setChallenges: (challenges) => setState(prev => ({ ...prev, challenges })),
    toggleTheme: () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }))
  };

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 overflow-hidden text-slate-900 dark:text-slate-100">
          <Sidebar isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} onLogout={logout} isGuest={isGuest} session={session} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={() => setIsMenuOpen(true)} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/wealth" element={<WealthProjections />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

