export default App;

import React, { useMemo, useState } from 'react';
import { useFinance } from '../App';
import { 
  TrendingUp, 
  TrendingDown, 
  Target, 
  PiggyBank,
  Wallet,
  CheckCircle2,
  Circle,
  ChevronUp,
  ChevronDown,
  Settings2,
  ChevronRight,
  Sparkles,
  Loader2,
  ShoppingBag
} from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';
import { generateAIChallenges } from '../services/geminiService';

const Dashboard: React.FC = () => {
  const { 
    accounts, 
    savings, 
    transactions, 
    challenges, 
    budgets,
    currentDate,
    dashboardLayout,
    updateLayout,
    setChallenges,
    getAccountHistoricalBalance,
    getSavingHistoricalBalance,
    getNetWorthHistorical, // Now using the new function
    viewMode,
    theme
  } = useFinance();

  const [isEditMode, setIsEditMode] = useState(false);
  const [chartFilter, setChartFilter] = useState<'6m' | '12m'>('12m');
  const [showBreakdown, setShowBreakdown] = useState(false);
  const [isGeneratingChallenges, setIsGeneratingChallenges] = useState(false);

  // Helper para identificar transacciones de ahorro
  const isSavingTx = (t: any) => t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId;

  // Lógica Financiera Corregida
  const metrics = useMemo(() => {
    let prevDateStr: string;
    if (viewMode === 'year') {
      prevDateStr = (parseInt(currentDate) - 1).toString();
    } else {
      const parts = currentDate.split('-').map(Number);
      const date = new Date(parts[0], parts[1] - 2, 1);
      const y = date.getFullYear();
      const m = String(date.getMonth() + 1).padStart(2, '0');
      prevDateStr = `${y}-${m}`;
    }

    const pastLiquidBalance = accounts.reduce((sum, acc) => sum + getAccountHistoricalBalance(acc.id, prevDateStr), 0);
    const monthTx = transactions.filter(t => t.date.startsWith(currentDate));

    const income = monthTx
      .filter(t => t.type === 'income' && !t.refundId && !isSavingTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    const refundRecoveries = monthTx
      .filter(t => t.type === 'income' && t.refundId)
      .reduce((sum, t) => sum + t.amount, 0);

    const spendingExits = monthTx
      .filter(t => t.type === 'expense' && !isSavingTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    const netSpending = Math.max(0, spendingExits - refundRecoveries);

    const monthSavings = monthTx
      .filter(t => t.type === 'expense' && isSavingTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    const monthResult = income - netSpending - monthSavings;
    const liquidity = pastLiquidBalance + monthResult;
    const totalSavingsAccumulated = savings.reduce((sum, s) => sum + getSavingHistoricalBalance(s.id, currentDate), 0);
    const netWorth = liquidity + totalSavingsAccumulated;

    return {
      income,
      expense: netSpending,
      monthSavings,
      monthResult,
      pastLiquidBalance,
      liquidity,
      totalSavingsAccumulated,
      netWorth,
      refundRecoveries
    };
  }, [transactions, currentDate, accounts, savings, getAccountHistoricalBalance, getSavingHistoricalBalance, viewMode]);

  // AI Challenges Auto-Evaluator
  const evaluatedChallenges = useMemo(() => {
    return challenges.map(ch => {
      const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
      let isCompleted = false;

      if (ch.type === 'spending_limit') {
        const spent = monthTx
          .filter(t => t.type === 'expense' && t.category === ch.category)
          .reduce((sum, t) => sum + t.amount, 0);
        isCompleted = spent <= ch.target && spent > 0;
      } else if (ch.type === 'savings_goal') {
        isCompleted = metrics.totalSavingsAccumulated >= ch.target;
      } else if (ch.type === 'income_target') {
        isCompleted = metrics.income >= ch.target;
      }

      return { ...ch, completed: isCompleted || ch.completed };
    });
  }, [challenges, transactions, currentDate, metrics]);

  // Chart Data
  const chartData = useMemo(() => {
    const monthNames = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
    const limit = chartFilter === '6m' ? 6 : 12;

    // Parse current date
    const currentYear = parseInt(currentDate.substring(0, 4));
    const currentMonthIndex = viewMode === 'month' ? parseInt(currentDate.substring(5, 7)) - 1 : 11; // 0-indexed month, for year view use Dec (11)

    const data = Array.from({ length: limit }).map((_, i) => {
        const date = new Date(currentYear, currentMonthIndex, 1);
        date.setMonth(date.getMonth() - (limit - 1 - i)); // Go back (limit - 1 - i) months from current period

        const displayMonthIndex = date.getMonth();
        const displayYear = date.getFullYear();

        // Construct the date string for historical lookup based on viewMode
        const dateStrForCalculation = viewMode === 'year' 
            ? displayYear.toString() 
            : `${displayYear}-${String(displayMonthIndex + 1).padStart(2, '0')}`;

        const patrimonio = getNetWorthHistorical(dateStrForCalculation); // Use the actual historical net worth

        return {
            name: monthNames[displayMonthIndex], // E.g., "Jul" for current, "Jun" for previous, etc.
            fullLabel: `${monthNames[displayMonthIndex]} ${displayYear}`, // For tooltip
            patrimonio: patrimonio // Actual historical net worth
        };
    });
    return data;
  }, [getNetWorthHistorical, chartFilter, currentDate, viewMode]); // Added getNetWorthHistorical and viewMode as dependencies

  const handleGenerateChallenges = async () => {
    setIsGeneratingChallenges(true);
    try {
      // Usar valores calculados dinámicamente para el contexto de la IA
      const budgetsInfo = budgets.map(b => {
        const calculatedSpent = transactions
          .filter(t => t.date.startsWith(currentDate) && t.category === b.category)
          .reduce((sum, t) => {
            if (b.type === 'expense') {
              if (t.type === 'expense') return sum + t.amount;
              if (t.type === 'income' && t.refundId) return sum - t.amount;
            }
            if (b.type === 'income' && t.type === 'income') return sum + t.amount;
            return sum;
          }, 0);
        return `${b.category}: ${calculatedSpent}/${b.limit}€`;
      }).join(", ");

      const context = `Presupuestos: ${budgetsInfo}. Patrimonio: ${metrics.netWorth}€. Ahorros: ${metrics.totalSavingsAccumulated}€.`;
      const newChallenges = await generateAIChallenges(context);
      setChallenges(newChallenges);
    } catch (error) {
      console.error("Error generating challenges:", error);
    } finally {
      setIsGeneratingChallenges(false);
    }
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    const newLayout = [...dashboardLayout];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newLayout.length) return;
    [newLayout[index], newLayout[targetIndex]] = [newLayout[targetIndex], newLayout[index]];
    updateLayout(newLayout);
  };

  const renderBlock = (key: string, index: number) => {
    const moveControls = isEditMode && (
      <div className="absolute top-4 right-4 flex gap-1 z-20">
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'up'); }} className="p-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-95" disabled={index === 0}>
          <ChevronUp size={16} className="text-slate-600 dark:text-slate-400" />
        </button>
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'down'); }} className="p-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-95" disabled={index === dashboardLayout.length - 1}>
          <ChevronDown size={16} className="text-slate-600 dark:text-slate-400" />
        </button>
      </div>
    );

    switch (key) {
      case 'balance':
        return (
          <div key={key} className="relative bg-[#2563eb] dark:bg-blue-600 rounded-[2.5rem] p-8 md:p-10 text-white shadow-2xl shadow-blue-200/50 dark:shadow-blue-900/20 overflow-hidden transition-colors duration-300">
            {moveControls}
            <div className="relative z-10 flex flex-col">
              <div className="flex justify-between items-start mb-10">
                <div>
                  <p className="text-blue-100 text-[9px] font-black uppercase tracking-[0.2em] mb-2 opacity-80">Patrimonio Neto en {currentDate}</p>
                  <h2 className="text-4xl md:text-5xl font-black tracking-tight">{metrics.netWorth.toLocaleString()}€</h2>
                </div>
                <button 
                  onClick={() => setShowBreakdown(!showBreakdown)}
                  className={`px-5 py-3 rounded-2xl flex items-center gap-2 text-xs font-black transition-all shadow-lg bg-white/20 backdrop-blur-md hover:bg-white/30 active:scale-95`}
                >
                  {metrics.monthResult >= 0 ? <TrendingUp size={16} /> : <TrendingDown size={16} />}
                  {metrics.monthResult >= 0 ? '+' : ''}{metrics.monthResult.toLocaleString()}€ en este mes
                  <ChevronDown size={14} className={`transition-transform duration-300 ${showBreakdown ? 'rotate-180' : ''}`} />
                </button>
              </div>

              {showBreakdown && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8 animate-in slide-in-from-top-4 duration-300">
                  <div className="p-5 bg-blue-400/30 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-blue-100">Ingresos del Mes</p>
                    <p className="text-2xl font-black">{metrics.income.toLocaleString()}€</p>
                  </div>
                  <div className="p-5 bg-[#4c51bf]/40 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-indigo-100">Gastos Netos Mes</p>
                    <p className="text-2xl font-black">{metrics.expense.toLocaleString()}€</p>
                    {metrics.refundRecoveries > 0 && (
                      <p className="text-[9px] font-bold text-indigo-200 opacity-80 mt-1">(-{metrics.refundRecoveries.toLocaleString()}€ de reembolsos)</p>
                    )}
                  </div>
                  <div className="p-5 bg-slate-500/30 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-slate-100">Ahorrado Mes</p>
                    <p className="text-2xl font-black">{metrics.monthSavings.toLocaleString()}€</p>
                  </div>
                </div>
              )}

              <div className="h-px bg-white/15 w-full mb-8"></div>

              <div className="grid grid-cols-3 gap-8">
                <div>
                  <p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Saldo Anterior</p>
                  <p className="text-xl md:text-2xl font-black">{metrics.pastLiquidBalance.toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Resultado Mes</p>
                  <p className="text-xl md:text-2xl font-black">{metrics.monthResult.toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Liquidez</p>
                  <p className="text-xl md:text-2xl font-black">{metrics.liquidity.toLocaleString()}€</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'challenges':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm h-full hover:shadow-md transition-all duration-300">
            {moveControls}
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <div className="w-10 h-10 bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 rounded-xl flex items-center justify-center transition-colors">
                  <Target size={20} />
                </div>
                <h3 className="font-bold text-slate-800 dark:text-slate-100">Retos AI Aura</h3>
              </div>
              <button 
                onClick={handleGenerateChallenges}
                disabled={isGeneratingChallenges}
                className="p-2.5 bg-blue-600 text-white rounded-xl transition-all disabled:opacity-50 hover:bg-blue-700 shadow-md shadow-blue-100 dark:shadow-none"
              >
                {isGeneratingChallenges ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />}
              </button>
            </div>
            <div className="space-y-3">
              {evaluatedChallenges.map(ch => (
                <div key={ch.id} className={`p-4 rounded-2xl border flex items-center gap-3 transition-all ${ch.completed ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-100 dark:border-emerald-800/50' : 'bg-slate-50 dark:bg-slate-800/50 border-slate-100 dark:border-slate-800'}`}>
                  {ch.completed ? <CheckCircle2 className="text-emerald-500" size={20}/> : <Circle className="text-slate-300 dark:text-slate-600" size={20}/>}
                  <div className="flex-1">
                    <p className={`text-sm font-bold ${ch.completed ? 'text-emerald-700 dark:text-emerald-300' : 'text-slate-700 dark:text-slate-300'}`}>{ch.title}</p>
                    <p className="text-[10px] text-slate-500 dark:text-slate-400 font-medium">Objetivo: {ch.target}€</p>
                  </div>
                </div>
              ))}
              {evaluatedChallenges.length === 0 && (
                <p className="text-slate-400 dark:text-slate-500 text-xs text-center py-4 italic">Pulsa en el destello para que Aura te proponga retos.</p>
              )}
            </div>
          </div>
        );
      case 'savings':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm h-full hover:shadow-md transition-all duration-300">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-amber-50 dark:bg-amber-900/40 text-amber-600 dark:text-amber-400 rounded-xl flex items-center justify-center transition-colors">
                <PiggyBank size={20} />
              </div>
              <h3 className="font-bold text-slate-800 dark:text-slate-100">Ahorro en {currentDate}</h3>
            </div>
            <div className="text-center py-6">
              <p className="text-4xl font-black text-slate-900 dark:text-white">{metrics.totalSavingsAccumulated.toLocaleString()}€</p>
              <p className="text-xs text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest mt-2">Capital acumulado histórico</p>
            </div>
            <div className="grid grid-cols-2 gap-2 mt-4">
               {savings.slice(0, 4).map(s => (
                 <div key={s.id} className="p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-800 transition-colors">
                   <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold truncate uppercase tracking-tighter">{s.name}</p>
                   <p className="text-xs font-black text-slate-700 dark:text-slate-200">{getSavingHistoricalBalance(s.id, currentDate)}€</p>
                 </div>
               ))}
            </div>
          </div>
        );
      case 'chart':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm transition-all duration-300">
            {moveControls}
            <div className="flex items-center justify-between mb-8">
              <h3 className="font-bold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                <TrendingUp size={20} className="text-emerald-500" /> Evolución del Patrimonio
              </h3>
              <div className="flex gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-xl">
                <button onClick={() => setChartFilter('6m')} className={`px-4 py-1.5 text-[10px] font-bold rounded-lg transition-all ${chartFilter === '6m' ? 'bg-white dark:bg-slate-700 shadow-sm text-blue-600 dark:text-blue-400' : 'text-slate-400 dark:text-slate-500'}`}>6 M</button>
                <button onClick={() => setChartFilter('12m')} className={`px-4 py-1.5 text-[10px] font-bold rounded-lg transition-all ${chartFilter === '12m' ? 'bg-white dark:bg-slate-700 shadow-sm text-blue-600 dark:text-blue-400' : 'text-slate-400 dark:text-slate-500'}`}>12 M</button>
              </div>
            </div>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="colorPat" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={theme === 'dark' ? '#1e293b' : '#f1f5f9'} />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: theme === 'dark' ? '#64748b' : '#94a3b8'}} />
                  <YAxis hide />
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', backgroundColor: theme === 'dark' ? '#0f172a' : '#fff', color: theme === 'dark' ? '#f1f5f9' : '#000' }}
                    itemStyle={{ color: theme === 'dark' ? '#3b82f6' : '#2563eb' }}
                    formatter={(value: any, name: string, props: any) => [`${value.toLocaleString()}€`, props.payload.fullLabel || 'Patrimonio']}
                  />
                  <Area type="monotone" dataKey="patrimonio" stroke="#3b82f6" strokeWidth={3} fill="url(#colorPat)" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>
        );
      case 'accounts':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm hover:shadow-md transition-all duration-300">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-emerald-50 dark:bg-emerald-900/40 text-emerald-600 dark:text-emerald-400 rounded-xl flex items-center justify-center transition-colors">
                <Wallet size={20} />
              </div>
              <h3 className="font-bold text-slate-800 dark:text-slate-100">Cuentas en {currentDate}</h3>
            </div>
            <div className="space-y-4">
              {accounts.map(acc => (
                <div key={acc.id} className="flex justify-between items-center p-4 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-slate-100 dark:border-slate-800 transition-colors">
                  <div className="flex items-center gap-3">
                    <span className="text-xl">{acc.emoji || '🏦'}</span>
                    <span className="font-bold text-slate-700 dark:text-slate-300 text-sm">{acc.name}</span>
                  </div>
                  <span className="font-black text-slate-900 dark:text-white">{getAccountHistoricalBalance(acc.id, currentDate).toLocaleString()}€</span>
                </div>
              ))}
            </div>
          </div>
        );
      case 'budget':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm h-full hover:shadow-md transition-all duration-300">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-purple-50 dark:bg-purple-900/40 text-purple-600 dark:text-purple-400 rounded-xl flex items-center justify-center transition-colors">
                <ShoppingBag size={20} />
              </div>
              <h3 className="font-bold text-slate-800 dark:text-slate-100">Presupuestos Mes</h3>
            </div>
            <div className="space-y-5">
              {budgets.slice(0, 3).map(b => {
                // Cálculo dinámico de lo gastado para el widget
                const budgetSpent = transactions
                  .filter(t => t.date.startsWith(currentDate) && t.category === b.category)
                  .reduce((sum, t) => {
                    if (b.type === 'expense') {
                      if (t.type === 'expense') return sum + t.amount;
                      if (t.type === 'income' && !!t.refundId) return sum - t.amount; // Restar reembolsos del gasto
                    }
                    if (b.type === 'income' && t.type === 'income') return sum + t.amount;
                    return sum;
                  }, 0);

                const progress = b.limit > 0 ? Math.min((budgetSpent / b.limit) * 100, 100) : 0;
                const isOverBudget = b.type === 'expense' && budgetSpent > b.limit;

                return (
                  <div key={b.id}>
                    <div className="flex justify-between text-[10px] font-bold text-slate-500 dark:text-slate-400 mb-1.5 uppercase tracking-wider">
                      <span>{b.category}</span>
                      <span style={{ color: isOverBudget ? '#f43f5e' : b.color }}>{Math.round(progress)}%</span>
                    </div>
                    <div className="w-full h-2 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                      <div 
                        className={`h-full transition-all duration-700`} 
                        style={{ 
                          width: `${progress}%`,
                          backgroundColor: isOverBudget ? '#f43f5e' : b.color || '#3b82f6'
                        }}
                      ></div>
                    </div>
                  </div>
                );
              })}
              {budgets.length === 0 && <p className="text-xs text-slate-400 dark:text-slate-500 italic text-center py-4">Sin límites definidos.</p>}
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="space-y-6 pb-20 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-2">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Dashboard</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight transition-colors">Análisis de {currentDate}. Saldos y gastos sincronizados.</p>
        </div>
        <button 
          onClick={() => setIsEditMode(!isEditMode)}
          className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-sm transition-all shadow-sm ${isEditMode ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 dark:shadow-blue-900/40' : 'bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700'}`}
        >
          <Settings2 size={18}/> {isEditMode ? 'Guardar Cambios' : 'Personalizar Diseño'}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 auto-rows-min">
        {dashboardLayout.map((key, idx) => {
          const isFullWidth = key === 'balance' || key === 'chart';
          return (
            <div key={key} className={`${isFullWidth ? 'lg:col-span-2' : 'lg:col-span-1'} transition-all duration-300`}>
              {renderBlock(key, idx)}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useMemo, createContext, useContext, useRef } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, useNavigate } from 'react-router-dom';
import { 
  LayoutDashboard, Wallet, PiggyBank, Receipt, BarChart3, 
  MessageSquare, Menu, X, Plus, Camera, CalendarDays, 
  CalendarRange, Sun, Moon, LineChart as LineChartIcon, 
  LogOut, Loader2, Sparkles, CloudCheck, CloudUpload, RefreshCw,
  ChevronLeft, ChevronRight, AlertTriangle, CloudOff
} from 'lucide-react';
import { FinanceState, Account, Saving, Refund, Transaction, Budget, AIChallenge } from './types';
import { INITIAL_DATA } from './constants';
import { supabase } from './services/supabase';

// Componentes de vistas
import Dashboard from './components/Dashboard.tsx';
import Accounts from './components/Accounts.tsx';
import Savings from './components/Savings.tsx';
import Refunds from './components/Refunds.tsx';
import Transactions from './components/Transactions.tsx';
import BudgetManager from './components/Budget.tsx';
import AIAdvisor from './components/AIAdvisor.tsx';
import WealthProjections from './components/WealthProjections.tsx';
import Login from './components/Login.tsx';

interface FinanceContextType extends FinanceState {
  getAccountHistoricalBalance: (accountId: string, dateStr: string) => number;
  getSavingHistoricalBalance: (savingId: string, dateStr: string) => number;
  getNetWorthHistorical: (dateStr: string) => number; // Added for historical net worth
  addTransaction: (t: Omit<Transaction, 'id'>, myPart?: number) => void;
  updateTransaction: (t: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addAccount: (a: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (a: Account) => void;
  deleteAccount: (id: string) => void;
  addSaving: (s: Omit<Saving, 'id'>) => void;
  updateSaving: (s: Saving) => void;
  deleteSaving: (id: string) => void;
  addRefund: (r: Omit<Refund, 'id'>) => void;
  updateRefund: (r: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addBudget: (b: Omit<Budget, 'id' | 'spent' | 'icon' | 'type'> & { type?: 'income' | 'expense'; icon?: string }) => void;
  updateBudget: (b: Budget) => void;
  deleteBudget: (id: string) => void;
  changePeriod: (offset: number) => void;
  setPeriod: (date: string) => void;
  setViewMode: (mode: 'month' | 'year') => void;
  updateLayout: (newLayout: string[]) => void;
  setChallenges: (challenges: AIChallenge[]) => void;
  toggleTheme: () => void;
  isGuest: boolean;
  isSyncing: boolean;
  syncError: boolean;
  loginAsGuest: () => void;
  retrySync: () => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);
export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [state, setState] = useState<FinanceState>(INITIAL_DATA as any);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState(false);
  const [dataLoadedFromCloud, setDataLoadedFromCloud] = useState(false);

  // 1. Manejo de Sesión y Carga de Datos
  useEffect(() => {
    const initApp = async () => {
      setIsLoading(true); // Asegurar que el estado de carga esté activo al inicio de la inicialización
      setSyncError(false); // Limpiar errores de sincronización anteriores
      try {
        console.log("App: Iniciando la aplicación...");
        const { data: { session: currentSession }, error: sessionError } = await supabase.auth.getSession();

        if (sessionError) {
          console.error("App: Error al obtener la sesión de Supabase:", sessionError.message || JSON.stringify(sessionError));
        }

        if (currentSession) {
          console.log("App: Sesión encontrada, obteniendo datos del usuario.");
          setSession(currentSession);
          setIsGuest(false);
          await fetchUserData(currentSession.user.id);
          console.log("App: Obtención de datos de usuario completada.");
        } else {
          console.log("App: No se encontró sesión, verificando modo invitado.");
          const guestFlag = localStorage.getItem('finanzas_pro_guest') === 'true';
          if (guestFlag) {
            console.log("App: Modo invitado habilitado.");
            setIsGuest(true);
            const savedState = localStorage.getItem('finanzas_pro_local_state');
            if (savedState) setState(JSON.parse(savedState));
            setDataLoadedFromCloud(false); // No hay datos de la nube en modo invitado
          } else {
            console.log("App: No hay sesión ni modo invitado. Se mostrará la pantalla de inicio de sesión.");
          }
        }
      } catch (err) {
        console.error("App: Fallo inesperado durante la inicialización (error crítico):", err instanceof Error ? err.message : JSON.stringify(err));
        setSyncError(true); // Indica que hubo un problema de sincronización/inicialización
      } finally {
        console.log("App: Secuencia de inicialización finalizada. Estableciendo isLoading(false).");
        setIsLoading(false); // SIEMPRE desactivar el indicador de carga al finalizar la inicialización.
      }
    };

    initApp();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, newSession) => {
      console.log(`App: Evento de cambio de estado de autenticación: ${_event}`);
      if (newSession) {
        console.log("App: Nueva sesión detectada, actualizando sesión y obteniendo datos.");
        setSession(newSession);
        setIsGuest(false);
        await fetchUserData(newSession.user.id);
      } else {
        console.log("App: Sesión finalizada o no detectada. Reseteando la aplicación (a menos que sea modo invitado).");
        if (localStorage.getItem('finanzas_pro_guest') !== 'true') {
          setSession(null);
          setIsGuest(false);
          setState(INITIAL_DATA as any);
          setDataLoadedFromCloud(false);
        }
      }
    });

    return () => {
      console.log("App: Desuscribiéndose de los cambios de estado de autenticación.");
      subscription.unsubscribe();
    };
  }, []);

  const fetchUserData = async (userId: string) => {
    setIsLoading(true); // Re-activa el estado de carga durante la obtención de datos
    setSyncError(false); // Limpiar errores de sincronización anteriores
    try {
      console.log(`App: Obteniendo perfil de usuario para ID: ${userId}`);
      const { data, error } = await supabase
        .from('profiles')
        .select('state')
        .eq('id', userId)
        .maybeSingle();

      if (error) {
        console.error("App: Error al obtener datos de perfil de usuario de Supabase:", error.message || JSON.stringify(error));
        throw error; // Propagate the error to the catch block
      }

      if (data && data.state) {
        console.log("App: Perfil de usuario encontrado y cargado.");
        setState(data.state);
        setDataLoadedFromCloud(true);
      } else { // No data found, user might be new or profile not initialized
        console.log("App: No se encontró perfil de usuario, creando perfil inicial.");
        // Create initial profile data
        const { error: upsertError } = await supabase
          .from('profiles')
          .upsert({ id: userId, state: INITIAL_DATA, updated_at: new Date().toISOString() });

        if (upsertError) {
          console.error("App: Error al insertar/actualizar perfil inicial de Supabase:", upsertError.message || JSON.stringify(upsertError));
          throw upsertError;
        }

        setState(INITIAL_DATA as any);
        setDataLoadedFromCloud(true);
        console.log("App: Perfil inicial creado exitosamente.");
      }
    } catch (err) {
      console.error("App: Error crítico de sincronización durante fetchUserData:", err instanceof Error ? err.message : JSON.stringify(err));
      setSyncError(true);
    } finally {
      console.log("App: fetchUserData finalizado. Estableciendo isLoading(false).");
      setIsLoading(false);
    }
  };

  // 2. Persistencia en la Nube con "Debounce" y Manejo de Conflictos
  useEffect(() => {
    if (!isLoading && !isSyncing) { // Solo si no está cargando la app inicialmente y no hay una sincronización en curso
      if (session && dataLoadedFromCloud) {
        const timer = setTimeout(async () => {
          console.log("App: Iniciando sincronización de datos con Supabase (debounce).");
          setIsSyncing(true);
          setSyncError(false); // Limpiar errores antes de intentar sincronizar
          try {
            const { error } = await supabase
              .from('profiles')
              .upsert({ 
                id: session.user.id, 
                state, 
                updated_at: new Date().toISOString() 
              });

            if (error) {
              console.error("App: Fallo al guardar en la nube:", error.message || JSON.stringify(error));
              throw error;
            }
            console.log("App: Sincronización de datos exitosa.");
          } catch (err) {
            console.error("App: Fallo al guardar en la nube (error de persistencia):", err instanceof Error ? err.message : JSON.stringify(err));
            setSyncError(true);
          } finally {
            setIsSyncing(false);
          }
        }, 2000); // 2 segundos de calma antes de subir cambios
        return () => clearTimeout(timer);
      } else if (isGuest) {
        console.log("App: Guardando estado localmente (modo invitado).");
        localStorage.setItem('finanzas_pro_local_state', JSON.stringify(state));
      }
    }
  }, [state, session, isGuest, isLoading, dataLoadedFromCloud, isSyncing]); // Agregado isSyncing como dependencia

  // Temas
  useEffect(() => {
    if (state.theme === 'dark') document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [state.theme]);

  const getAccountHistoricalBalance = (accountId: string, dateLimit: string) => {
    const account = state.accounts.find(a => a.id === accountId);
    if (!account) return 0;
    // dateLimit could be YYYY-MM or YYYY. Normalize to YYYY-MM-DD for comparison.
    const effectiveDateLimit = dateLimit.length === 4 ? `${dateLimit}-12-31` : `${dateLimit}-31`; 
    const relevantTransactions = state.transactions.filter(t => t.accountId === accountId && t.date <= effectiveDateLimit);
    return relevantTransactions.reduce((acc, t) => acc + (t.type === 'income' ? t.amount : -t.amount), account.initialBalance);
  };

  const getSavingHistoricalBalance = (savingId: string, dateLimit: string) => {
    const relevant = state.transactions.filter(t => t.savingId === savingId && t.date <= (dateLimit.length === 4 ? `${dateLimit}-12-31` : `${dateLimit}-31`));
    return relevant.reduce((acc, t) => acc + t.amount, 0);
  };

  const getNetWorthHistorical = (dateStr: string) => {
    const totalLiquidCapital = state.accounts.reduce((sum, acc) => sum + getAccountHistoricalBalance(acc.id, dateStr), 0);
    const totalSavingsAccumulated = state.savings.reduce((sum, s) => sum + getSavingHistoricalBalance(s.id, dateStr), 0);
    return totalLiquidCapital + totalSavingsAccumulated;
  };

  const loginAsGuest = () => {
    console.log("App: Iniciando sesión como invitado.");
    localStorage.setItem('finanzas_pro_guest', 'true');
    setIsGuest(true);
    const saved = localStorage.getItem('finanzas_pro_local_state');
    if (saved) setState(JSON.parse(saved));
    else setState(INITIAL_DATA as any);
    setIsLoading(false); // Ensure loading state is turned off for guest mode
    setSyncError(false); // Asegurar que no haya errores de sincronización en modo invitado
  };

  const logout = () => {
    console.log("App: Cerrando sesión.");
    localStorage.removeItem('finanzas_pro_guest');
    localStorage.removeItem('finanzas_pro_local_state');
    setIsGuest(false);
    setSession(null);
    setDataLoadedFromCloud(false);
    supabase.auth.signOut();
  };

  const retrySync = () => {
    console.log("App: Reintentando sincronización...");
    if (session) fetchUserData(session.user.id);
  };

  if (isLoading) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950">
        <div className="relative mb-6">
          <div className="w-20 h-20 border-4 border-blue-500/20 rounded-full border-t-blue-500 animate-spin"></div>
          <Wallet className="absolute inset-0 m-auto text-blue-600 animate-pulse" size={32} />
        </div>
        <p className="text-slate-500 font-black uppercase tracking-[0.2em] text-[10px] animate-pulse">Sincronizando Bóveda Digital...</p>
        {syncError && (
          <div className="mt-4 flex items-center gap-2 p-3 bg-rose-50 dark:bg-rose-900/20 rounded-xl border border-rose-100 dark:border-rose-900/40 animate-in fade-in zoom-in duration-300">
            <AlertTriangle className="text-rose-600" size={16} />
            <p className="text-rose-600 text-xs font-medium">Error al cargar datos. Comprueba tu conexión o configuración de Supabase.</p>
            <button onClick={retrySync} className="p-1.5 rounded-md bg-rose-100 dark:bg-rose-800 text-rose-700 dark:text-rose-300 hover:bg-rose-200 dark:hover:bg-rose-700 transition-colors">
              <RefreshCw size={14} />
            </button>
          </div>
        )}
      </div>
    );
  }

  if (!session && !isGuest) {
    return <Login onGuestLogin={loginAsGuest} />;
  }

  const contextValue: FinanceContextType = {
    ...state,
    getAccountHistoricalBalance,
    getSavingHistoricalBalance,
    getNetWorthHistorical, // Added to context
    isGuest,
    isSyncing,
    syncError,
    loginAsGuest,
    retrySync,
    addTransaction: (t, myPart) => {
      const id = 'tx_' + Math.random().toString(36).substr(2, 9);
      let finalTx = { ...t, id };
      let newRefunds = [...state.refunds];
      if (t.type === 'expense' && t.isRefund) {
        const refundId = 'ref_' + Date.now();
        const partToPay = myPart !== undefined ? myPart : t.amount / 2;
        newRefunds.push({ id: refundId, name: t.description, totalAmount: t.amount, paidByMe: partToPay, pendingAmount: t.amount - partToPay, status: 'open', notes: 'Auto', date: t.date, category: t.category, originTransactionId: id });
        finalTx.refundId = refundId;
      }
      setState(prev => ({ ...prev, transactions: [finalTx as Transaction, ...prev.transactions], refunds: newRefunds }));
    },
    updateTransaction: (updatedTx) => setState(prev => ({ ...prev, transactions: prev.transactions.map(t => t.id === updatedTx.id ? updatedTx : t) })),
    deleteTransaction: (id) => setState(prev => ({ ...prev, transactions: prev.transactions.filter(tx => tx.id !== id) })),
    addAccount: (a) => setState(prev => ({ ...prev, accounts: [...prev.accounts, { ...a, id: 'acc_' + Date.now(), currentBalance: a.initialBalance } as Account] })),
    updateAccount: (a) => setState(prev => ({ ...prev, accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc) })),
    deleteAccount: (id) => setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) })),
    addSaving: (s) => setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id: 'sav_' + Date.now() } as Saving] })),
    updateSaving: (s) => setState(prev => ({ ...prev, savings: prev.savings.map(sv => sv.id === s.id ? s : sv) })),
    deleteSaving: (id) => setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) })),
    addRefund: (r) => setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id: 'ref_' + Date.now() } as Refund] })),
    updateRefund: (r) => setState(prev => ({ ...prev, refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf) })),
    deleteRefund: (id) => setState(prev => ({ ...prev, refunds: prev.refunds.filter(r => r.id !== id) })),
    mergeRefunds: (id1, id2) => {
      const r1 = state.refunds.find(r => r.id === id1);
      const r2 = state.refunds.find(r => r.id === id2);
      if (!r1 || !r2) return;
      const merged: Refund = {
        id: 'ref_' + Date.now(),
        name: `${r1.name} + ${r2.name}`,
        totalAmount: r1.totalAmount + r2.totalAmount,
        paidByMe: r1.paidByMe + r2.paidByMe,
        pendingAmount: r1.pendingAmount + r2.pendingAmount,
        status: (r1.status === 'open' || r2.status === 'open') ? 'open' : 'closed',
        notes: `Fusionado: ${r1.notes} | ${r2.notes}`,
        date: new Date().toISOString(),
        category: r1.category
      };
      setState(prev => ({
        ...prev,
        refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), merged]
      }));
    },
    addBudget: (b) => setState(prev => ({ ...prev, budgets: [...prev.budgets, { ...b, id: 'budget_' + Date.now(), spent: 0 } as Budget] })),
    updateBudget: (b) => setState(prev => ({ ...prev, budgets: prev.budgets.map(bg => bg.id === b.id ? bg : bg) })),
    deleteBudget: (id) => setState(prev => ({ ...prev, budgets: prev.budgets.filter(b => b.id !== id) })),
    changePeriod: (offset) => {
      const [year, month] = state.currentDate.split('-').map(Number);
      // For year view, month is not used, so adjust year
      const newDate = state.viewMode === 'year' 
        ? new Date(year + offset, 0, 1) // Jan 1 of the new year
        : new Date(year, (month || 1) - 1 + offset, 1); // Month view

      const newDateStr = state.viewMode === 'year' 
        ? newDate.getFullYear().toString() 
        : `${newDate.getFullYear()}-${String(newDate.getMonth() + 1).padStart(2, '0')}`;
      setState(prev => ({ ...prev, currentDate: newDateStr }));
    },
    setPeriod: (dateStr) => setState(prev => ({ ...prev, currentDate: dateStr })),
    setViewMode: (mode) => setState(prev => ({ ...prev, viewMode: mode })),
    updateLayout: (newLayout) => setState(prev => ({ ...prev, dashboardLayout: newLayout })),
    setChallenges: (challenges) => setState(prev => ({ ...prev, challenges })),
    toggleTheme: () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }))
  };

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 overflow-hidden text-slate-900 dark:text-slate-100 font-sans">
          <Sidebar isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} onLogout={logout} isGuest={isGuest} session={session} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={() => setIsMenuOpen(true)} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/wealth" element={<WealthProjections />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

const Sidebar = ({ isOpen, onClose, onLogout, isGuest, session }: { isOpen: boolean, onClose: () => void, onLogout: () => void, isGuest: boolean, session: any }) => {
  const location = useLocation();
  const { isSyncing, syncError, retrySync } = useFinance();

  const menuItems = [
    { path: '/', icon: <LayoutDashboard size={20} />, label: 'Dashboard' },
    { path: '/accounts', icon: <Wallet size={20} />, label: 'Cuentas' },
    { path: '/savings', icon: <PiggyBank size={20} />, label: 'Ahorro' },
    { path: '/wealth', icon: <LineChartIcon size={20} />, label: 'Proyecciones' },
    { path: '/refunds', icon: <Receipt size={20} />, label: 'Reembolsos' },
    { path: '/transactions', icon: <BarChart3 size={20} />, label: 'Transacciones' },
    { path: '/budget', icon: <Receipt size={20} />, label: 'Presupuesto' },
    { path: '/advisor', icon: <MessageSquare size={20} />, label: 'Asesor IA' },
  ];

  return (
    <>
      {isOpen && <div className="fixed inset-0 bg-slate-900/60 dark:bg-black/60 backdrop-blur-sm z-40 md:hidden" onClick={onClose} />}
