  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [state, setState] = useState<FinanceState>(INITIAL_DATA as any);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState(false);
  const [dataLoadedFromCloud, setDataLoadedFromCloud] = useState(false);

  // 1. Manejo de Sesión y Carga de Datos
  useEffect(() => {
    const initApp = async () => {
      setIsLoading(true); // Asegurar que el estado de carga esté activo al inicio de la inicialización
      setSyncError(false); // Limpiar errores de sincronización anteriores
      try {
        console.log("App: Iniciando la aplicación...");
        const { data: { session: currentSession }, error: sessionError } = await supabase.auth.getSession();

        if (sessionError) {
          console.error("App: Error al obtener la sesión de Supabase:", sessionError.message || JSON.stringify(sessionError));
        }

        if (currentSession) {
          console.log("App: Sesión encontrada, obteniendo datos del usuario.");
          setSession(currentSession);
          setIsGuest(false);
          await fetchUserData(currentSession.user.id);
          console.log("App: Obtención de datos de usuario completada.");
        } else {
          console.log("App: No se encontró sesión, verificando modo invitado.");
          const guestFlag = localStorage.getItem('finanzas_pro_guest') === 'true';
          if (guestFlag) {
            console.log("App: Modo invitado habilitado.");
            setIsGuest(true);
            const savedState = localStorage.getItem('finanzas_pro_local_state');
            if (savedState) setState(JSON.parse(savedState));
            setDataLoadedFromCloud(false); // No hay datos de la nube en modo invitado
          } else {
            console.log("App: No hay sesión ni modo invitado. Se mostrará la pantalla de inicio de sesión.");
          }
        }
      } catch (err) {
        console.error("App: Fallo inesperado durante la inicialización (error crítico):", err instanceof Error ? err.message : JSON.stringify(err));
        setSyncError(true); // Indica que hubo un problema de sincronización/inicialización
      } finally {
        console.log("App: Secuencia de inicialización finalizada. Estableciendo isLoading(false).");
        setIsLoading(false); // SIEMPRE desactivar el indicador de carga al finalizar la inicialización.
      }
    };

    initApp();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, newSession) => {
      console.log(`App: Evento de cambio de estado de autenticación: ${_event}`);
      if (newSession) {
        console.log("App: Nueva sesión detectada, actualizando sesión y obteniendo datos.");
        setSession(newSession);
        setIsGuest(false);
        await fetchUserData(newSession.user.id);
      } else {
        console.log("App: Sesión finalizada o no detectada. Reseteando la aplicación (a menos que sea modo invitado).");
        if (localStorage.getItem('finanzas_pro_guest') !== 'true') {
          setSession(null);
          setIsGuest(false);
          setState(INITIAL_DATA as any);
          setDataLoadedFromCloud(false);
        }
      }
    });

    return () => {
      console.log("App: Desuscribiéndose de los cambios de estado de autenticación.");
      subscription.unsubscribe();
    };
  }, []);

  const fetchUserData = async (userId: string) => {
    setIsLoading(true); // Re-activa el estado de carga durante la obtención de datos
    setSyncError(false); // Limpiar errores de sincronización anteriores
    try {
      console.log(`App: Obteniendo perfil de usuario para ID: ${userId}`);
      const { data, error } = await supabase
        .from('profiles')
        .select('state')
        .eq('id', userId)
        .maybeSingle();

      if (error) {
        console.error("App: Error al obtener datos de perfil de usuario de Supabase:", error.message || JSON.stringify(error));
        throw error; // Propagate the error to the catch block
      }

      if (data && data.state) {
        console.log("App: Perfil de usuario encontrado y cargado.");
        setState(data.state);
        setDataLoadedFromCloud(true);
      } else { // No data found, user might be new or profile not initialized
        console.log("App: No se encontró perfil de usuario, creando perfil inicial.");
        // Create initial profile data
        const { error: upsertError } = await supabase
          .from('profiles')
          .upsert({ id: userId, state: INITIAL_DATA, updated_at: new Date().toISOString() });

        if (upsertError) {
          console.error("App: Error al insertar/actualizar perfil inicial de Supabase:", upsertError.message || JSON.stringify(upsertError));
          throw upsertError;
        }

        setState(INITIAL_DATA as any);
        setDataLoadedFromCloud(true);
        console.log("App: Perfil inicial creado exitosamente.");
      }
    } catch (err) {
      console.error("App: Error crítico de sincronización durante fetchUserData:", err instanceof Error ? err.message : JSON.stringify(err));
      setSyncError(true);
    } finally {
      console.log("App: fetchUserData finalizado. Estableciendo isLoading(false).");
      setIsLoading(false);
    }
  };

  // 2. Persistencia en la Nube con "Debounce" y Manejo de Conflictos
  useEffect(() => {
    if (!isLoading && !isSyncing) { // Solo si no está cargando la app inicialmente y no hay una sincronización en curso
      if (session && dataLoadedFromCloud) {
        const timer = setTimeout(async () => {
          console.log("App: Iniciando sincronización de datos con Supabase (debounce).");
          setIsSyncing(true);
          setSyncError(false); // Limpiar errores antes de intentar sincronizar
          try {
            const { error } = await supabase
              .from('profiles')
              .upsert({ 
                id: session.user.id, 
                state, 
                updated_at: new Date().toISOString() 
              });

            if (error) {
              console.error("App: Fallo al guardar en la nube:", error.message || JSON.stringify(error));
              throw error;
            }
            console.log("App: Sincronización de datos exitosa.");
          } catch (err) {
            console.error("App: Fallo al guardar en la nube (error de persistencia):", err instanceof Error ? err.message : JSON.stringify(err));
            setSyncError(true);
          } finally {
            setIsSyncing(false);
          }
        }, 2000); // 2 segundos de calma antes de subir cambios
        return () => clearTimeout(timer);
      } else if (isGuest) {
        console.log("App: Guardando estado localmente (modo invitado).");
        localStorage.setItem('finanzas_pro_local_state', JSON.stringify(state));
      }
    }
  }, [state, session, isGuest, isLoading, dataLoadedFromCloud, isSyncing]); // Agregado isSyncing como dependencia

  // Temas
  useEffect(() => {
    if (state.theme === 'dark') document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [state.theme]);

  const getAccountHistoricalBalance = (accountId: string, dateLimit: string) => {
    const account = state.accounts.find(a => a.id === accountId);
    if (!account) return 0;
    // dateLimit could be YYYY-MM or YYYY. Normalize to YYYY-MM-DD for comparison.
    const effectiveDateLimit = dateLimit.length === 4 ? `${dateLimit}-12-31` : `${dateLimit}-31`; 
    const relevantTransactions = state.transactions.filter(t => t.accountId === accountId && t.date <= effectiveDateLimit);
    return relevantTransactions.reduce((acc, t) => acc + (t.type === 'income' ? t.amount : -t.amount), account.initialBalance);
  };

  const getSavingHistoricalBalance = (savingId: string, dateLimit: string) => {
    const relevant = state.transactions.filter(t => t.savingId === savingId && t.date <= (dateLimit.length === 4 ? `${dateLimit}-12-31` : `${dateLimit}-31`));
    return relevant.reduce((acc, t) => acc + t.amount, 0);
  };

  const getNetWorthHistorical = (dateStr: string) => {
    const totalLiquidCapital = state.accounts.reduce((sum, acc) => sum + getAccountHistoricalBalance(acc.id, dateStr), 0);
    const totalSavingsAccumulated = state.savings.reduce((sum, s) => sum + getSavingHistoricalBalance(s.id, dateStr), 0);
    return totalLiquidCapital + totalSavingsAccumulated;
  };

  const loginAsGuest = () => {
    console.log("App: Iniciando sesión como invitado.");
    localStorage.setItem('finanzas_pro_guest', 'true');
    setIsGuest(true);
    const saved = localStorage.getItem('finanzas_pro_local_state');
    if (saved) setState(JSON.parse(saved));
    else setState(INITIAL_DATA as any);
    setIsLoading(false); // Ensure loading state is turned off for guest mode
    setSyncError(false); // Asegurar que no haya errores de sincronización en modo invitado
  };

  const logout = () => {
    console.log("App: Cerrando sesión.");
    localStorage.removeItem('finanzas_pro_guest');
    localStorage.removeItem('finanzas_pro_local_state');
    setIsGuest(false);
    setSession(null);
    setDataLoadedFromCloud(false);
    supabase.auth.signOut();
  };

  const retrySync = () => {
    console.log("App: Reintentando sincronización...");
    if (session) fetchUserData(session.user.id);
  };

  if (isLoading) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950">
        <div className="relative mb-6">
          <div className="w-20 h-20 border-4 border-blue-500/20 rounded-full border-t-blue-500 animate-spin"></div>
          <Wallet className="absolute inset-0 m-auto text-blue-600 animate-pulse" size={32} />
        </div>
        <p className="text-slate-500 font-black uppercase tracking-[0.2em] text-[10px] animate-pulse">Sincronizando Bóveda Digital...</p>
        {syncError && (
          <div className="mt-4 flex items-center gap-2 p-3 bg-rose-50 dark:bg-rose-900/20 rounded-xl border border-rose-100 dark:border-rose-900/40 animate-in fade-in zoom-in duration-300">
            <AlertTriangle className="text-rose-600" size={16} />
            <p className="text-rose-600 text-xs font-medium">Error al cargar datos. Comprueba tu conexión o configuración de Supabase.</p>
            <button onClick={retrySync} className="p-1.5 rounded-md bg-rose-100 dark:bg-rose-800 text-rose-700 dark:text-rose-300 hover:bg-rose-200 dark:hover:bg-rose-700 transition-colors">
              <RefreshCw size={14} />
            </button>
          </div>
        )}
      </div>
    );
  }

  if (!session && !isGuest) {
    return <Login onGuestLogin={loginAsGuest} />;
  }

  const contextValue: FinanceContextType = {
    ...state,
    getAccountHistoricalBalance,
    getSavingHistoricalBalance,
    getNetWorthHistorical, // Added to context
    isGuest,
    isSyncing,
    syncError,
    loginAsGuest,
    retrySync,
    addTransaction: (t, myPart) => {
      const id = 'tx_' + Math.random().toString(36).substr(2, 9);
      let finalTx = { ...t, id };
      let newRefunds = [...state.refunds];
      if (t.type === 'expense' && t.isRefund) {
        const refundId = 'ref_' + Date.now();
        const partToPay = myPart !== undefined ? myPart : t.amount / 2;
        newRefunds.push({ id: refundId, name: t.description, totalAmount: t.amount, paidByMe: partToPay, pendingAmount: t.amount - partToPay, status: 'open', notes: 'Auto', date: t.date, category: t.category, originTransactionId: id });
        finalTx.refundId = refundId;
      }
      setState(prev => ({ ...prev, transactions: [finalTx as Transaction, ...prev.transactions], refunds: newRefunds }));
    },
    updateTransaction: (updatedTx) => setState(prev => ({ ...prev, transactions: prev.transactions.map(t => t.id === updatedTx.id ? updatedTx : t) })),
    deleteTransaction: (id) => setState(prev => ({ ...prev, transactions: prev.transactions.filter(tx => tx.id !== id) })),
    addAccount: (a) => setState(prev => ({ ...prev, accounts: [...prev.accounts, { ...a, id: 'acc_' + Date.now(), currentBalance: a.initialBalance } as Account] })),
    updateAccount: (a) => setState(prev => ({ ...prev, accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc) })),
    deleteAccount: (id) => setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) })),
    addSaving: (s) => setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id: 'sav_' + Date.now() } as Saving] })),
    updateSaving: (s) => setState(prev => ({ ...prev, savings: prev.savings.map(sv => sv.id === s.id ? s : sv) })),
    deleteSaving: (id) => setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) })),
    addRefund: (r) => setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id: 'ref_' + Date.now() } as Refund] })),
    updateRefund: (r) => setState(prev => ({ ...prev, refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf) })),
    deleteRefund: (id) => setState(prev => ({ ...prev, refunds: prev.refunds.filter(r => r.id !== id) })),
    mergeRefunds: (id1, id2) => {
      const r1 = state.refunds.find(r => r.id === id1);
      const r2 = state.refunds.find(r => r.id === id2);
      if (!r1 || !r2) return;
      const merged: Refund = {
        id: 'ref_' + Date.now(),
        name: `${r1.name} + ${r2.name}`,
        totalAmount: r1.totalAmount + r2.totalAmount,
        paidByMe: r1.paidByMe + r2.paidByMe,
        pendingAmount: r1.pendingAmount + r2.pendingAmount,
        status: (r1.status === 'open' || r2.status === 'open') ? 'open' : 'closed',
        notes: `Fusionado: ${r1.notes} | ${r2.notes}`,
        date: new Date().toISOString(),
        category: r1.category
      };
      setState(prev => ({
        ...prev,
        refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), merged]
      }));
    },
    addBudget: (b) => setState(prev => ({ ...prev, budgets: [...prev.budgets, { ...b, id: 'budget_' + Date.now(), spent: 0 } as Budget] })),
    updateBudget: (b) => setState(prev => ({ ...prev, budgets: prev.budgets.map(bg => bg.id === b.id ? bg : bg) })),
    deleteBudget: (id) => setState(prev => ({ ...prev, budgets: prev.budgets.filter(b => b.id !== id) })),
    changePeriod: (offset) => {
      const [year, month] = state.currentDate.split('-').map(Number);
      // For year view, month is not used, so adjust year
      const newDate = state.viewMode === 'year' 
        ? new Date(year + offset, 0, 1) // Jan 1 of the new year
        : new Date(year, (month || 1) - 1 + offset, 1); // Month view

      const newDateStr = state.viewMode === 'year' 
        ? newDate.getFullYear().toString() 
        : `${newDate.getFullYear()}-${String(newDate.getMonth() + 1).padStart(2, '0')}`;
      setState(prev => ({ ...prev, currentDate: newDateStr }));
    },
    setPeriod: (dateStr) => setState(prev => ({ ...prev, currentDate: dateStr })),
    setViewMode: (mode) => setState(prev => ({ ...prev, viewMode: mode })),
    updateLayout: (newLayout) => setState(prev => ({ ...prev, dashboardLayout: newLayout })),
    setChallenges: (challenges) => setState(prev => ({ ...prev, challenges })),
    toggleTheme: () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }))
  };

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 overflow-hidden text-slate-900 dark:text-slate-100 font-sans">
          <Sidebar isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} onLogout={logout} isGuest={isGuest} session={session} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={() => setIsMenuOpen(true)} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/wealth" element={<WealthProjections />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

const Sidebar = ({ isOpen, onClose, onLogout, isGuest, session }: { isOpen: boolean, onClose: () => void, onLogout: () => void, isGuest: boolean, session: any }) => {
  const location = useLocation();
  const { isSyncing, syncError, retrySync } = useFinance();

  const menuItems = [
    { path: '/', icon: <LayoutDashboard size={20} />, label: 'Dashboard' },
    { path: '/accounts', icon: <Wallet size={20} />, label: 'Cuentas' },
    { path: '/savings', icon: <PiggyBank size={20} />, label: 'Ahorro' },
    { path: '/wealth', icon: <LineChartIcon size={20} />, label: 'Proyecciones' },
    { path: '/refunds', icon: <Receipt size={20} />, label: 'Reembolsos' },
    { path: '/transactions', icon: <BarChart3 size={20} />, label: 'Transacciones' },
    { path: '/budget', icon: <Receipt size={20} />, label: 'Presupuesto' },
    { path: '/advisor', icon: <MessageSquare size={20} />, label: 'Asesor IA' },
  ];

  return (
    <>
      {isOpen && <div className="fixed inset-0 bg-slate-900/60 dark:bg-black/60 backdrop-blur-sm z-40 md:hidden" onClick={onClose} />}
      <aside className={`fixed md:static inset-y-0 left-0 w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 shadow-xl md:shadow-sm z-50 flex flex-col transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <div className="p-6 flex items-center justify-between">
          <h1 className="text-xl font-bold text-blue-600 dark:text-blue-400 flex items-center gap-2">
            <div className="w-8 h-8 bg-blue-600 dark:bg-blue-500 rounded-lg flex items-center justify-center text-white"><Wallet size={18} /></div>
            Finanzas Pro
          </h1>
          <button onClick={onClose} className="md:hidden p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"><X size={20} /></button>
        </div>

        <div className="mx-4 mb-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-slate-100 dark:border-slate-800">
             <div className="flex items-center gap-3 mb-2">
               {isGuest ? (
                 <Sparkles className="text-amber-500 shrink-0" size={16} />
               ) : (
                 <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center text-white font-black text-[10px] shrink-0">
                   {session?.user?.email?.substring(0,2).toUpperCase()}
                 </div>
               )}
               <div className="flex-1 min-w-0">
                 <p className="text-[10px] font-black text-slate-600 dark:text-slate-300 uppercase tracking-widest truncate">
                   {isGuest ? 'Modo Local' : session?.user?.email}
                 </p>
                 <div className="flex items-center gap-1.5 mt-0.5">
                   {isGuest ? (
                     <p className="text-[8px] text-amber-500 font-bold uppercase">Sin Sincronizar</p>
                   ) : syncError ? (
                     <button onClick={retrySync} className="flex items-center gap-1 group">
                       <CloudOff size={10} className="text-rose-500" />
                       <p className="text-[8px] text-rose-500 font-bold uppercase group-hover:underline">Error de Red (Reintentar)</p>
                     </button>
                   ) : isSyncing ? (
                     <><RefreshCw size={8} className="animate-spin text-blue-500" /><p className="text-[8px] text-blue-500 font-bold uppercase">Subiendo...</p></>
                   ) : (
                     <><CloudCheck size={10} className="text-emerald-500" /><p className="text-[8px] text-emerald-500 font-bold uppercase">Sincronizado</p></>
                   )}
                 </div>
               </div>
             </div>
             {syncError && !isGuest && (
               <div className="flex items-center gap-2 mt-2 p-2 bg-rose-50 dark:bg-rose-900/20 rounded-xl border border-rose-100 dark:border-rose-900/40">
                 <AlertTriangle className="text-rose-600" size={12} />
                 <p className="text-[8px] text-rose-600 font-medium">Tus cambios se guardan localmente hasta conectar.</p>
               </div>
             )}
        </div>

        <nav className="flex-1 px-4 space-y-1 overflow-y-auto custom-scrollbar">
          {menuItems.map((item) => (
            <Link key={item.path} to={item.path} onClick={onClose} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 ${location.pathname === item.path ? 'bg-blue-600 text-white font-semibold shadow-lg shadow-blue-100 dark:shadow-none' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-800 dark:hover:text-slate-200'}`}>
              {item.icon} <span className="text-sm">{item.label}</span>
            </Link>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-100 dark:border-slate-800">
           <button onClick={onLogout} className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl transition-all font-bold text-sm">
             <LogOut size={20} /> Salir de la App
           </button>
        </div>
      </aside>
    </>
  );
};

const Header = ({ onMenuClick }: { onMenuClick: () => void }) => {
  const { currentDate, changePeriod, setPeriod, viewMode, setViewMode, theme, toggleTheme } = useFinance();
  const monthNames = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];
  const [isPeriodDropdownOpen, setIsPeriodDropdownOpen] = useState(false);

  const currentFormatted = useMemo(() => {
    if (viewMode === 'year') return `Año ${currentDate}`;
    const parts = currentDate.split('-').map(Number);
    return parts.length === 2 ? `${monthNames[parts[1] - 1] || ''} ${parts[0]}` : currentDate;
  }, [currentDate, viewMode]);

  return (
    <header className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 h-16 flex items-center justify-between px-4 md:px-6 sticky top-0 z-40 transition-all duration-300">
      <div className="flex items-center gap-3">
        <button onClick={onMenuClick} className="md:hidden p-2 text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"><Menu size={22} /></button>
        <div className="flex items-center gap-2">
          <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-xl shadow-inner mr-2">
             <button onClick={() => setViewMode('month')} className={`p-1.5 rounded-lg transition-all ${viewMode === 'month' ? 'bg-white dark:bg-slate-700 shadow-sm text-blue-600 dark:text-blue-400' : 'text-slate-400'}`}><CalendarDays size={18} /></button>
             <button onClick={() => setViewMode('year')} className={`p-1.5 rounded-lg transition-all ${viewMode === 'year' ? 'bg-white dark:bg-slate-700 shadow-sm text-blue-600 dark:text-blue-400' : 'text-slate-400'}`}><CalendarRange size={18} /></button>
          </div>
          <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-xl shadow-inner relative">
            <button onClick={() => changePeriod(-1)} className="p-1 hover:bg-white dark:hover:bg-slate-700 rounded-lg transition-all dark:text-slate-400"><ChevronLeft size={18} /></button>
            <button 
              onClick={() => setIsPeriodDropdownOpen(!isPeriodDropdownOpen)} 
              className="px-3 py-1.5 text-xs font-black text-slate-700 dark:text-slate-300 min-w-[110px] text-center uppercase tracking-wider cursor-pointer hover:bg-white/50 dark:hover:bg-slate-700/50 rounded-lg"
            >
              {currentFormatted}
            </button>
            <button onClick={() => changePeriod(1)} className="p-1 hover:bg-white dark:hover:bg-slate-700 rounded-lg transition-all dark:text-slate-400"><ChevronRight size={18} /></button>

            {isPeriodDropdownOpen && (
              <PeriodDropdown
                currentDate={currentDate}
                viewMode={viewMode}
                setPeriod={(date) => { setPeriod(date); setIsPeriodDropdownOpen(false); }}
                onClose={() => setIsPeriodDropdownOpen(false)}
              />
            )}
          </div>
        </div>
      </div>
      <button onClick={toggleTheme} className="p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 shadow-sm transition-all">
        {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
      </button>
    </header>
  );
};

const PeriodDropdown: React.FC<{
  currentDate: string;
  viewMode: 'month' | 'year';
  setPeriod: (date: string) => void;
  onClose: () => void;
}> = ({ currentDate, viewMode, setPeriod, onClose }) => {
  const monthNames = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];
  const currentYear = parseInt(currentDate.substring(0, 4));
  // currentMonth is 0-indexed for comparison with monthNames array index
  const currentMonth = viewMode === 'month' && currentDate.length === 7 ? parseInt(currentDate.substring(5, 7)) - 1 : -1; 

  // For closing when clicking outside
  const dropdownRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        onClose();
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [onClose]);


  return (
    <div ref={dropdownRef} className="absolute top-full left-1/2 -translate-x-1/2 mt-2 bg-white dark:bg-slate-900 rounded-2xl shadow-xl z-50 p-2 border border-slate-100 dark:border-slate-700 animate-in fade-in slide-in-from-top-2 duration-200">
      {viewMode === 'month' ? (
        <div className="grid grid-cols-3 gap-2 px-1 max-w-[360px]"> {/* Aumentado max-w */}
          {monthNames.map((name, index) => (
            <button
              key={index}
              onClick={() => setPeriod(`${currentYear}-${String(index + 1).padStart(2, '0')}`)}
              className={`block px-2 py-2 text-xs font-semibold rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors whitespace-nowrap overflow-hidden text-ellipsis ${ /* Reducido px */
                  index === currentMonth ? 'bg-blue-600 text-white' : 'text-slate-700 dark:text-slate-300'
              }`}
            >
              {name}
            </button>
          ))}
        </div>
      ) : (
        <div className="grid grid-cols-2 gap-2 px-1 max-w-[240px] max-h-60 overflow-y-auto custom-scrollbar"> {/* Updated for years: increased max-w */}
          {Array.from({ length: 11 }, (_, i) => currentYear - 5 + i).map(year => ( // 5 years before, current, 5 years after
            <button
              key={year}
              onClick={() => setPeriod(year.toString())}
              className={`block px-2 py-2 text-xs font-semibold rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors whitespace-nowrap overflow-hidden text-ellipsis ${ /* Updated for years: reduced px */
                  year === currentYear ? 'bg-blue-600 text-white' : 'text-slate-700 dark:text-slate-300'
              }`}
            >
              Año {year}
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

