                  <button onClick={(e) => { e.stopPropagation(); if(confirm('¿Seguro que quieres eliminar este presupuesto?')) deleteBudget(b.id); }} className="p-2.5 text-slate-400 hover:text-rose-600 hover:bg-rose-50 dark:hover:bg-rose-900/40 rounded-xl transition-colors"><Trash2 size={18} /></button>
                </div>
