  const [isAppInitializing, setIsAppInitializing] = useState(true); // Nuevo estado para la carga inicial de la app
  const [isSyncing, setIsSyncing] = useState(false); // Para sincronizaciones de datos en segundo plano
  const [syncError, setSyncError] = useState(false); // Errores de sincronización (tanto inicial como en segundo plano)
  const [initializationTimeout, setInitializationTimeout] = useState(false); // Para detectar un timeout en la carga inicial
  const [dataLoadedFromCloud, setDataLoadedFromCloud] = useState(false);

  // Define fetchUserData as a useCallback to ensure a stable function reference
  const fetchUserData = useCallback(async (userId: string) => {
    setIsSyncing(true); // Activa el estado de sincronización para la obtención de datos
    setSyncError(false); // Limpiar errores de sincronización anteriores
    try {
      console.log(`App: Obteniendo perfil de usuario para ID: ${userId}`);
      const { data, error } = await supabase
        .from('profiles')
        .select('state')
        .eq('id', userId)
        .maybeSingle();

      if (error) {
        console.error("App: Error al obtener datos de perfil de usuario de Supabase:", error.message || JSON.stringify(error));
        throw error; // Propagate the error to the catch block
      }

      if (data && data.state) {
        console.log("App: Perfil de usuario encontrado y cargado.");
        setState(data.state);
        setDataLoadedFromCloud(true);
      } else { // No data found, user might be new or profile not initialized
        console.log("App: No se encontró perfil de usuario, creando perfil inicial.");
        // Create initial profile data
        const { error: upsertError } = await supabase
          .from('profiles')
          .upsert({ id: userId, state: INITIAL_DATA, updated_at: new Date().toISOString() });

        if (upsertError) {
          console.error("App: Error al insertar/actualizar perfil inicial de Supabase:", upsertError.message || JSON.stringify(upsertError));
          throw upsertError;
        }

        setState(INITIAL_DATA as any);
        setDataLoadedFromCloud(true);
        console.log("App: Perfil inicial creado exitosamente.");
      }
    } catch (err) {
      console.error("App: Error crítico de sincronización durante fetchUserData:", err instanceof Error ? err.message : JSON.stringify(err));
      setSyncError(true); // Indica que hubo un problema de sincronización de datos
    } finally {
      console.log("App: fetchUserData finalizado. Estableciendo isSyncing(false).");
      setIsSyncing(false); // SIEMPRE desactivar el indicador de sincronización.
    }
  }, [setIsSyncing, setSyncError, setState, setDataLoadedFromCloud]);


  // Define loginAsGuest as a useCallback for a stable function reference
  const loginAsGuest = useCallback(() => {
    console.log("App: Iniciando sesión como invitado.");
    localStorage.setItem('finanzas_pro_guest', 'true');
    setIsGuest(true);
    const saved = localStorage.getItem('finanzas_pro_local_state');
    if (saved) setState(JSON.parse(saved));
    else setState(INITIAL_DATA as any);
    setIsAppInitializing(false); // Asegurar que el estado de carga inicial esté desactivado para el modo invitado
    setSyncError(false); // Asegurar que no haya errores de sincronización en modo invitado
    setInitializationTimeout(false); // Limpiar el timeout si se entra en modo invitado
  }, [setIsGuest, setState, setIsAppInitializing, setSyncError, setInitializationTimeout]);

  // Define initApp as a useCallback for a stable function reference
  const initApp = useCallback(async () => {
    setIsAppInitializing(true); // Asegurar que el estado de carga inicial esté activo
    setSyncError(false); // Limpiar errores de sincronización anteriores
    setInitializationTimeout(false); // Limpiar flag de timeout anterior

    // Establecer un timeout para la inicialización global de la aplicación
    let timeoutId: number;
    timeoutId = window.setTimeout(() => {
        console.warn("App: La inicialización de la aplicación ha excedido el tiempo límite.");
        setInitializationTimeout(true); // Indicar un posible problema
        setSyncError(true); // Indicar un posible problema
        setIsAppInitializing(false); // Forzar la desactivación de la pantalla de carga
    }, 15000); // 15 segundos de tiempo límite

    try {
      console.log("App: Iniciando la aplicación...");
      const { data: { session: currentSession }, error: sessionError } = await supabase.auth.getSession();

      if (sessionError) {
        console.error("App: Error al obtener la sesión de Supabase:", sessionError.message || JSON.stringify(sessionError));
        throw sessionError; // Propagar el error al bloque catch
      }

      if (currentSession) {
        console.log("App: Sesión encontrada, obteniendo datos del usuario.");
        setSession(currentSession);
        setIsGuest(false);
        await fetchUserData(currentSession.user.id); // fetchUserData ahora usa isSyncing
        console.log("App: Obtención de datos de usuario completada.");
      } else {
        console.log("App: No se encontró sesión, verificando modo invitado.");
        const guestFlag = localStorage.getItem('finanzas_pro_guest') === 'true';
        if (guestFlag) {
          console.log("App: Modo invitado habilitado.");
          setIsGuest(true);
          const savedState = localStorage.getItem('finanzas_pro_local_state');
          if (savedState) setState(JSON.parse(savedState));
          setDataLoadedFromCloud(false); // No hay datos de la nube en modo invitado
        } else {
          console.log("App: No hay sesión ni modo invitado. Se mostrará la pantalla de inicio de sesión.");
          setSession(null); // Asegurar que session sea null si no se encuentra sesión
          setIsGuest(false);
          setDataLoadedFromCloud(false);
          setState(INITIAL_DATA as any); // Resetear estado para una experiencia de login limpia
        }
      }
    } catch (err) {
      console.error("App: Fallo inesperado durante la inicialización (error crítico):", err instanceof Error ? err.message : JSON.stringify(err));
      setSyncError(true); // Indica que hubo un problema de sincronización/inicialización
    } finally {
      console.log("App: Secuencia de inicialización finalizada. Estableciendo isAppInitializing(false).");
      window.clearTimeout(timeoutId); // Limpiar timeout si la inicialización terminó antes
      setIsAppInitializing(false); // SIEMPRE desactivar el indicador de carga inicial al finalizar.
    }
  }, [fetchUserData, setSession, setIsGuest, setState, setIsAppInitializing, setSyncError, setInitializationTimeout, setDataLoadedFromCloud]);

  // Define retrySync as a useCallback for a stable function reference
  const retrySync = useCallback(async () => {
    console.log("App: Reintentando sincronización...");
    setSyncError(false); // Clear the error for the retry

    if (isAppInitializing) { // If the initial loading screen is active
      initApp(); // Retry the complete initialization
    } else if (session) { // If the app is already started and there's a session
      // Immediately attempt to upsert the current local state to the cloud
      // This addresses the "modifications not saved while stuck in 'subiendo'"
      setIsSyncing(true); // Activate the sync indicator
      let persistenceRetryTimeoutId: number;

      persistenceRetryTimeoutId = window.setTimeout(() => {
        console.warn("App: El reintento de sincronización de datos ha excedido el tiempo límite.");
        setSyncError(true); // Indicate a sync problem
        setIsSyncing(false); // Force turn off isSyncing
      }, 10000); // 10 seconds for retry persistence

      try {
        const { error } = await supabase
          .from('profiles')
          .upsert({ 
            id: session.user.id, 
            state, // Use current local state
            updated_at: new Date().toISOString() 
          });

        if (error) {
          console.error("App: Fallo al reintentar guardar en la nube:", error.message || JSON.stringify(error));
          throw error;
        }
        console.log("App: Reintento de sincronización exitoso.");
      } catch (err) {
        console.error("App: Fallo al reintentar guardar en la nube (error de persistencia):", err instanceof Error ? err.message : JSON.stringify(err));
        setSyncError(true);
      } finally {
        window.clearTimeout(persistenceRetryTimeoutId); // Clear timeout if operation finished
        setIsSyncing(false); // Always reset sync status
      }
    } else {
      console.log("App: No hay sesión para reintentar sincronización de datos de usuario, o ya es modo invitado.");
    }
  }, [isAppInitializing, session, initApp, state, setIsSyncing, setSyncError]);


  // 1. Manejo de Sesión y Carga de Datos
  useEffect(() => {
    initApp();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, newSession) => {
      console.log(`App: Evento de cambio de estado de autenticación: ${_event}`);
      // Solo reaccionar a eventos no iniciales si no estamos en modo invitado
      if (localStorage.getItem('finanzas_pro_guest') !== 'true') {
        if (newSession) {
          console.log("App: Nueva sesión detectada, actualizando sesión y obteniendo datos.");
          setSession(newSession);
          setIsGuest(false);
          await fetchUserData(newSession.user.id);
        } else {
          // Si el evento es SIGNED_OUT o una sesión inválida
          console.log("App: Sesión finalizada o no detectada. Reseteando la aplicación (no es modo invitado).");
          setSession(null);
          setIsGuest(false);
          setState(INITIAL_DATA as any); // Limpiar el estado al cerrar sesión
